import React, { useState, useMemo, useRef, useEffect } from 'react';
import { DollarSign, Package, Copy, Check, Search, User, FileText, RefreshCw, Handshake, Percent, Gift, Box, Repeat, History, Plus, Trash2, Save, ShoppingBag, ArrowRight, LayoutGrid } from 'lucide-react';
import { useStore } from '../contexts/StoreContext';
import { Client } from '../types';

// Mock Data for "Quick Catalog" - Fallback if history is empty
const QUICK_PRODUCTS = [
    { code: '10213', name: 'CAFE MELITTA 500G', price: 16.12 },
    { code: '10214', name: 'CAFE MELITTA 250G', price: 8.45 },
    { code: '5050', name: 'TORRADA BAUDUCCO', price: 5.99 },
    { code: '3020', name: 'BOLINHO BAUDUCCO', price: 2.15 },
    { code: '7788', name: 'BISC. RECHEADO', price: 3.50 },
];

interface NegotiationHistoryItem {
    id: string;
    timestamp: number;
    clientName: string;
    productName: string;
    price: number;
    quantity: number;
    type: 'bonus' | 'discount';
    bonusQty: number;
    bonusType: 'same' | 'different';
    bonusProduct: string;
    bonusProductPrice: number;
    targetPrice: number;
}

interface ComboItem {
    id: string;
    productName: string;
    quantity: number;
    unitPrice: number;
}

interface Combo {
    id: string;
    name: string;
    items: ComboItem[];
    totalValue: number;
}

export const Negotiate: React.FC = () => {
  const { state } = useStore();
  const [activeTab, setActiveTab] = useState<'generator' | 'combos'>('generator');
  const [history, setHistory] = useState<NegotiationHistoryItem[]>([]);
  const [combos, setCombos] = useState<Combo[]>([]);
  const [isCreatingCombo, setIsCreatingCombo] = useState(false);
  const [newComboName, setNewComboName] = useState('');
  const [newComboItems, setNewComboItems] = useState<ComboItem[]>([
      { id: '1', productName: '', quantity: 1, unitPrice: 0 }
  ]);

  // States for Generator
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [clientSearch, setClientSearch] = useState('');
  const [isClientDropdownOpen, setIsClientDropdownOpen] = useState(false);
  const [isProductDropdownOpen, setIsProductDropdownOpen] = useState(false);
  const [productName, setProductName] = useState(''); 
  const [quantity, setQuantity] = useState('');
  const [pricePalm, setPricePalm] = useState('');
  const [negotiationType, setNegotiationType] = useState<'bonus' | 'discount'>('bonus');
  const [bonusType, setBonusType] = useState<'same' | 'different'>('same');
  const [bonusProduct, setBonusProduct] = useState(''); 
  const [bonusQty, setBonusQty] = useState('0');
  const [bonusProductPrice, setBonusProductPrice] = useState('');
  const [targetPrice, setTargetPrice] = useState('');
  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);
  const [comboCopySuccess, setComboCopySuccess] = useState<string | null>(null);

  const clientDropdownRef = useRef<HTMLDivElement>(null);
  const productDropdownRef = useRef<HTMLDivElement>(null);
  const resultRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedHist = localStorage.getItem('metacheck_negotiation_history');
    if (savedHist) setHistory(JSON.parse(savedHist));
    const savedCombos = localStorage.getItem('metacheck_combos');
    if (savedCombos) setCombos(JSON.parse(savedCombos));
  }, []);

  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  const smartProducts = useMemo(() => {
      const historyMap = new Map();
      history.forEach(h => {
         if (!historyMap.has(h.productName)) {
             historyMap.set(h.productName, { name: h.productName, price: h.price, source: 'history', lastDate: h.timestamp });
         }
      });
      QUICK_PRODUCTS.forEach(qp => {
          const fullName = `${qp.code} - ${qp.name}`;
          if (!historyMap.has(fullName)) {
              historyMap.set(fullName, { name: fullName, price: qp.price, source: 'catalog', lastDate: 0 });
          }
      });
      let all = Array.from(historyMap.values());
      if (productName) all = all.filter(p => p.name.toLowerCase().includes(productName.toLowerCase()));
      return all.sort((a, b) => b.lastDate - a.lastDate).slice(0, 8);
  }, [productName, history]);

  const genStats = useMemo(() => {
      const qty = parseInt(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const totalValueSystem = qty * price;
      let finalPrice = price;
      let investmentPercent = 0;
      let bonusValueTotal = 0;

      if (negotiationType === 'bonus') {
          const bQty = parseInt(bonusQty) || 0;
          if (bonusType === 'same') {
              finalPrice = (qty + bQty) > 0 ? totalValueSystem / (qty + bQty) : price;
              bonusValueTotal = bQty * price;
              investmentPercent = qty > 0 ? (bQty / qty) * 100 : 0; 
          } else {
              const otherPrice = parseFloat(bonusProductPrice.replace(',', '.')) || 0;
              bonusValueTotal = bQty * otherPrice;
              finalPrice = qty > 0 ? (totalValueSystem - bonusValueTotal) / qty : 0;
              investmentPercent = totalValueSystem > 0 ? (bonusValueTotal / totalValueSystem) * 100 : 0;
          }
      } else {
          const target = parseFloat(targetPrice.replace(',', '.')) || price;
          finalPrice = target;
          investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
          bonusValueTotal = (price - target) * qty; 
      }
      return { totalValueSystem, finalPrice, investmentPercent, bonusValueTotal };
  }, [quantity, pricePalm, bonusQty, targetPrice, negotiationType, bonusType, bonusProductPrice]);

  const handleGenerate = () => {
      if (!selectedClient || !productName) return alert("Selecione cliente e produto");

      const text = `
🛒 *PROPOSTA COMERCIAL*
Cliente: ${selectedClient.name}
Produto: ${productName.toUpperCase()}
Quantidade: ${quantity}

*Condição:* ${negotiationType === 'bonus' ? 'Bonificação' : 'Desconto'}
Preço Tabela: R$ ${parseFloat(pricePalm || '0').toFixed(2)}
*Preço Final: R$ ${genStats.finalPrice.toFixed(2)}*
Economia: ${genStats.investmentPercent.toFixed(1)}%
      `.trim();

      setGeneratedText(text);
      const newItem = { id: Date.now().toString(), timestamp: Date.now(), clientName: selectedClient.name, productName, price: parseFloat(pricePalm), quantity: parseInt(quantity), type: negotiationType, bonusQty: parseInt(bonusQty), bonusType, bonusProduct, bonusProductPrice: parseFloat(bonusProductPrice), targetPrice: parseFloat(targetPrice) };
      const newHist = [newItem, ...history].slice(0, 20);
      setHistory(newHist);
      localStorage.setItem('metacheck_negotiation_history', JSON.stringify(newHist));
  };

  const saveCombo = () => {
      const combo = { id: Date.now().toString(), name: newComboName, items: newComboItems.filter(i => i.productName), totalValue: newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0) };
      const updated = [combo, ...combos];
      setCombos(updated);
      localStorage.setItem('metacheck_combos', JSON.stringify(updated));
      setIsCreatingCombo(false);
      setNewComboName('');
      setNewComboItems([{ id: '1', productName: '', quantity: 1, unitPrice: 0 }]);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Handshake className="text-brand-600" /> Negociação
            </h2>
            <p className="text-sm text-slate-500">Otimize suas propostas de venda</p>
        </div>
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner">
            <button onClick={() => setActiveTab('generator')} className={`flex-1 px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'generator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Gerador</button>
            <button onClick={() => setActiveTab('combos')} className={`flex-1 px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'combos' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Meus Combos</button>
        </div>
      </div>

      {activeTab === 'generator' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-30">
              <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block">Cliente</label>
              <div className="relative" ref={clientDropdownRef}>
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                <input type="text" value={clientSearch} onChange={(e) => { setClientSearch(e.target.value); setIsClientDropdownOpen(true); }} onFocus={() => setIsClientDropdownOpen(true)} className="w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-medium" placeholder="Buscar cliente..." />
                {isClientDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-48 overflow-y-auto z-40">
                    {filteredClients.map(c => (
                      <button key={c.id} onClick={() => { setSelectedClient(c); setClientSearch(c.name); setIsClientDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors">
                        <p className="font-bold text-sm text-slate-900 dark:text-white">{c.name}</p>
                        <p className="text-[10px] text-slate-500">#{c.code}</p>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-20">
              <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block">Produto</label>
              <div className="relative" ref={productDropdownRef}>
                <input type="text" value={productName} onChange={(e) => { setProductName(e.target.value); setIsProductDropdownOpen(true); }} onFocus={() => setIsProductDropdownOpen(true)} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-bold" placeholder="Nome ou Código..." />
                {isProductDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-48 overflow-y-auto z-40">
                    {smartProducts.map((p, i) => (
                      <button key={i} onClick={() => { setProductName(p.name); setPricePalm(p.price.toString()); setIsProductDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 flex justify-between items-center">
                        <div className="min-w-0 pr-2">
                           <p className="font-bold text-xs text-slate-700 dark:text-slate-300 truncate">{p.name}</p>
                           {p.source === 'history' && <span className="text-[8px] bg-amber-100 text-amber-700 px-1 rounded">HISTÓRICO</span>}
                        </div>
                        <span className="text-xs font-bold text-emerald-600">R$ {p.price.toFixed(2)}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
              <div className="grid grid-cols-2 gap-3 mt-4">
                <input type="number" placeholder="Qtd" value={quantity} onChange={(e) => setQuantity(e.target.value)} className="p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none" />
                <input type="number" placeholder="Preço Tabela" value={pricePalm} onChange={(e) => setPricePalm(e.target.value)} className="p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none" />
              </div>
            </div>

            <div className="bg-slate-900 p-5 rounded-2xl shadow-lg text-white">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] font-bold text-emerald-400 uppercase">Ação</h3>
                <div className="flex bg-white/10 p-1 rounded-lg">
                  <button onClick={() => setNegotiationType('bonus')} className={`px-3 py-1.5 rounded-md text-[10px] font-bold ${negotiationType === 'bonus' ? 'bg-emerald-500 text-white' : 'text-slate-400'}`}>Bonificar</button>
                  <button onClick={() => setNegotiationType('discount')} className={`px-3 py-1.5 rounded-md text-[10px] font-bold ${negotiationType === 'discount' ? 'bg-emerald-500 text-white' : 'text-slate-400'}`}>Desconto</button>
                </div>
              </div>
              {negotiationType === 'bonus' ? (
                <div className="space-y-3">
                  <input type="number" placeholder="Qtd Bonificada" value={bonusQty} onChange={(e) => setBonusQty(e.target.value)} className="w-full p-3 bg-white/10 border border-white/10 rounded-xl text-sm font-bold outline-none focus:border-emerald-500" />
                  <div className="flex justify-between items-center border-t border-white/10 pt-3">
                    <span className="text-xs text-slate-400">Preço Médio</span>
                    <span className="text-2xl font-black">R$ {genStats.finalPrice.toFixed(2)}</span>
                  </div>
                </div>
              ) : (
                <div className="space-y-3">
                  <input type="number" placeholder="Preço Target" value={targetPrice} onChange={(e) => setTargetPrice(e.target.value)} className="w-full p-3 bg-white/10 border border-white/10 rounded-xl text-sm font-bold outline-none focus:border-emerald-500" />
                  <div className="flex justify-between items-center border-t border-white/10 pt-3">
                    <span className="text-xs text-slate-400">Desconto</span>
                    <span className="text-2xl font-black">{genStats.investmentPercent.toFixed(1)}%</span>
                  </div>
                </div>
              )}
            </div>

            <button onClick={handleGenerate} className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 sticky bottom-4 md:static z-40">
                <FileText size={18} /> Gerar Negociação
            </button>
          </div>

          <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col min-h-[300px]" ref={resultRef}>
            <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-950/50">
                <h3 className="font-bold text-xs text-slate-500">RESUMO</h3>
                <button onClick={() => { navigator.clipboard.writeText(generatedText); setCopySuccess(true); setTimeout(() => setCopySuccess(false), 2000); }} disabled={!generatedText} className={`p-2 rounded-lg ${copySuccess ? 'text-emerald-500 bg-emerald-50' : 'text-slate-400 bg-slate-100'}`}>
                    {copySuccess ? <Check size={16} /> : <Copy size={16} />}
                </button>
            </div>
            <textarea readOnly value={generatedText} className="flex-1 p-5 outline-none bg-transparent text-sm font-mono text-slate-800 dark:text-slate-300 resize-none" placeholder="O resumo aparecerá aqui..." />
          </div>
        </div>
      )}

      {activeTab === 'combos' && (
        <div className="animate-in fade-in">
          {!isCreatingCombo ? (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Favoritos</h3>
                <button onClick={() => setIsCreatingCombo(true)} className="bg-brand-600 text-white px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 shadow-md">
                    <Plus size={16} /> Novo Combo
                </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {combos.map(c => (
                  <div key={c.id} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl p-4 shadow-sm group">
                    <div className="flex justify-between mb-3">
                       <h4 className="font-bold text-sm text-slate-800 dark:text-white uppercase">{c.name}</h4>
                       <div className="flex gap-2">
                          <button onClick={() => deleteCombo(c.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={14} /></button>
                          <button onClick={() => { copyCombo(c); setComboCopySuccess(c.id); setTimeout(() => setComboCopySuccess(null), 2000); }} className={`p-2 rounded-lg ${comboCopySuccess === c.id ? 'bg-emerald-50 text-emerald-600' : 'bg-brand-50 text-brand-600'}`}>
                             {comboCopySuccess === c.id ? <Check size={14}/> : <Copy size={14}/>}
                          </button>
                       </div>
                    </div>
                    <div className="space-y-1 bg-slate-50 dark:bg-slate-800/50 p-2 rounded-lg">
                       {c.items.map((it, idx) => (
                         <div key={idx} className="flex justify-between text-[10px] text-slate-500">
                           <span className="truncate pr-2">{it.quantity}x {it.productName}</span>
                           <span className="font-bold">R$ {it.unitPrice.toFixed(2)}</span>
                         </div>
                       ))}
                    </div>
                    <div className="mt-3 text-right">
                       <p className="text-xs font-black text-brand-600">Total: R$ {c.totalValue.toFixed(2)}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="bg-white dark:bg-slate-900 rounded-2xl border p-6 space-y-4 animate-in slide-in-from-right-4">
                <input value={newComboName} onChange={e => setNewComboName(e.target.value)} placeholder="Nome do Combo (ex: Mix Padaria)" className="w-full p-4 bg-slate-50 dark:bg-slate-950 border rounded-xl font-bold outline-none focus:ring-2 focus:ring-brand-500" />
                <div className="space-y-2">
                   {newComboItems.map(item => (
                     <div key={item.id} className="grid grid-cols-12 gap-2">
                        <input value={item.productName} onChange={e => updateComboItem(item.id, 'productName', e.target.value)} placeholder="Produto" className="col-span-6 p-2 bg-slate-50 dark:bg-slate-950 border rounded-lg text-xs" />
                        <input type="number" value={item.quantity} onChange={e => updateComboItem(item.id, 'quantity', parseFloat(e.target.value) || 0)} className="col-span-2 p-2 bg-slate-50 dark:bg-slate-950 border rounded-lg text-xs text-center" />
                        <input type="number" value={item.unitPrice} onChange={e => updateComboItem(item.id, 'unitPrice', parseFloat(e.target.value) || 0)} className="col-span-3 p-2 bg-slate-50 dark:bg-slate-950 border rounded-lg text-xs" />
                        <button onClick={() => handleRemoveComboItem(item.id)} className="col-span-1 text-slate-300 hover:text-red-500 flex justify-center items-center"><Trash2 size={16}/></button>
                     </div>
                   ))}
                   <button onClick={() => setNewComboItems([...newComboItems, { id: Date.now().toString(), productName: '', quantity: 1, unitPrice: 0 }])} className="w-full py-2 border border-dashed rounded-xl text-[10px] font-bold text-slate-400 hover:bg-slate-50">+ ADICIONAR ITEM</button>
                </div>
                <div className="flex justify-between items-center pt-4 border-t">
                    <p className="text-lg font-black text-brand-600">Total: R$ {newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0).toFixed(2)}</p>
                    <div className="flex gap-2">
                        <button onClick={() => setIsCreatingCombo(false)} className="px-4 py-2 text-xs font-bold text-slate-400">Cancelar</button>
                        <button onClick={saveCombo} className="bg-brand-600 text-white px-6 py-2 rounded-xl font-bold text-xs shadow-lg shadow-brand-500/20">Salvar</button>
                    </div>
                </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { DollarSign, Package, Copy, Check, Search, User, FileText, RefreshCw, Handshake, Percent, Gift, Box, Repeat, History, Plus, Trash2, Save, ShoppingBag, ArrowRight, LayoutGrid } from 'lucide-react';
import { useStore } from '../contexts/StoreContext';
import { Client } from '../types';

// Mock Data for "Quick Catalog" - Fallback if history is empty
const QUICK_PRODUCTS = [
    { code: '10213', name: 'CAFE MELITTA 500G', price: 16.12 },
    { code: '10214', name: 'CAFE MELITTA 250G', price: 8.45 },
    { code: '5050', name: 'TORRADA BAUDUCCO', price: 5.99 },
    { code: '3020', name: 'BOLINHO BAUDUCCO', price: 2.15 },
    { code: '7788', name: 'BISC. RECHEADO', price: 3.50 },
];

interface NegotiationHistoryItem {
    id: string;
    timestamp: number;
    clientName: string;
    productName: string;
    price: number;
    quantity: number;
    type: 'bonus' | 'discount';
    bonusQty: number;
    bonusType: 'same' | 'different';
    bonusProduct: string;
    bonusProductPrice: number;
    targetPrice: number;
}

interface ComboItem {
    id: string;
    productName: string;
    quantity: number;
    unitPrice: number;
}

interface Combo {
    id: string;
    name: string;
    items: ComboItem[];
    totalValue: number;
}

export const Negotiate: React.FC = () => {
  const { state } = useStore();
  const [activeTab, setActiveTab] = useState<'generator' | 'combos'>('generator');
  const [history, setHistory] = useState<NegotiationHistoryItem[]>([]);
  const [combos, setCombos] = useState<Combo[]>([]);
  const [isCreatingCombo, setIsCreatingCombo] = useState(false);
  const [newComboName, setNewComboName] = useState('');
  const [newComboItems, setNewComboItems] = useState<ComboItem[]>([
      { id: '1', productName: '', quantity: 1, unitPrice: 0 }
  ]);

  // States for Generator
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [clientSearch, setClientSearch] = useState('');
  const [isClientDropdownOpen, setIsClientDropdownOpen] = useState(false);
  const [isProductDropdownOpen, setIsProductDropdownOpen] = useState(false);
  const [productName, setProductName] = useState(''); 
  const [quantity, setQuantity] = useState('');
  const [pricePalm, setPricePalm] = useState('');
  const [negotiationType, setNegotiationType] = useState<'bonus' | 'discount'>('bonus');
  const [bonusType, setBonusType] = useState<'same' | 'different'>('same');
  const [bonusProduct, setBonusProduct] = useState(''); 
  const [bonusQty, setBonusQty] = useState('0');
  const [bonusProductPrice, setBonusProductPrice] = useState('');
  const [targetPrice, setTargetPrice] = useState('');
  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);
  const [comboCopySuccess, setComboCopySuccess] = useState<string | null>(null);

  const clientDropdownRef = useRef<HTMLDivElement>(null);
  const productDropdownRef = useRef<HTMLDivElement>(null);
  const resultRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedHist = localStorage.getItem('metacheck_negotiation_history');
    if (savedHist) setHistory(JSON.parse(savedHist));
    const savedCombos = localStorage.getItem('metacheck_combos');
    if (savedCombos) setCombos(JSON.parse(savedCombos));
  }, []);

  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  const smartProducts = useMemo(() => {
      const historyMap = new Map();
      history.forEach(h => {
         if (!historyMap.has(h.productName)) {
             historyMap.set(h.productName, { name: h.productName, price: h.price, source: 'history', lastDate: h.timestamp });
         }
      });
      QUICK_PRODUCTS.forEach(qp => {
          const fullName = `${qp.code} - ${qp.name}`;
          if (!historyMap.has(fullName)) {
              historyMap.set(fullName, { name: fullName, price: qp.price, source: 'catalog', lastDate: 0 });
          }
      });
      let all = Array.from(historyMap.values());
      if (productName) all = all.filter(p => p.name.toLowerCase().includes(productName.toLowerCase()));
      return all.sort((a, b) => b.lastDate - a.lastDate).slice(0, 8);
  }, [productName, history]);

  const genStats = useMemo(() => {
      const qty = parseInt(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const totalValueSystem = qty * price;
      let finalPrice = price;
      let investmentPercent = 0;
      let bonusValueTotal = 0;

      if (negotiationType === 'bonus') {
          const bQty = parseInt(bonusQty) || 0;
          if (bonusType === 'same') {
              finalPrice = (qty + bQty) > 0 ? totalValueSystem / (qty + bQty) : price;
              bonusValueTotal = bQty * price;
              investmentPercent = qty > 0 ? (bQty / qty) * 100 : 0; 
          } else {
              const otherPrice = parseFloat(bonusProductPrice.replace(',', '.')) || 0;
              bonusValueTotal = bQty * otherPrice;
              finalPrice = qty > 0 ? (totalValueSystem - bonusValueTotal) / qty : 0;
              investmentPercent = totalValueSystem > 0 ? (bonusValueTotal / totalValueSystem) * 100 : 0;
          }
      } else {
          const target = parseFloat(targetPrice.replace(',', '.')) || price;
          finalPrice = target;
          investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
          bonusValueTotal = (price - target) * qty; 
      }
      return { totalValueSystem, finalPrice, investmentPercent, bonusValueTotal };
  }, [quantity, pricePalm, bonusQty, targetPrice, negotiationType, bonusType, bonusProductPrice]);

  const handleGenerate = () => {
      if (!selectedClient || !productName) return alert("Selecione cliente e produto");

      const text = `
🛒 *PROPOSTA COMERCIAL*
Cliente: ${selectedClient.name}
Produto: ${productName.toUpperCase()}
Quantidade: ${quantity}

*Condição:* ${negotiationType === 'bonus' ? 'Bonificação' : 'Desconto'}
Preço Tabela: R$ ${parseFloat(pricePalm || '0').toFixed(2)}
*Preço Final: R$ ${genStats.finalPrice.toFixed(2)}*
Economia: ${genStats.investmentPercent.toFixed(1)}%
      `.trim();

      setGeneratedText(text);
      const newItem = { id: Date.now().toString(), timestamp: Date.now(), clientName: selectedClient.name, productName, price: parseFloat(pricePalm), quantity: parseInt(quantity), type: negotiationType, bonusQty: parseInt(bonusQty), bonusType, bonusProduct, bonusProductPrice: parseFloat(bonusProductPrice), targetPrice: parseFloat(targetPrice) };
      const newHist = [newItem, ...history].slice(0, 20);
      setHistory(newHist);
      localStorage.setItem('metacheck_negotiation_history', JSON.stringify(newHist));
  };

  const saveCombo = () => {
      const combo = { id: Date.now().toString(), name: newComboName, items: newComboItems.filter(i => i.productName), totalValue: newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0) };
      const updated = [combo, ...combos];
      setCombos(updated);
      localStorage.setItem('metacheck_combos', JSON.stringify(updated));
      setIsCreatingCombo(false);
      setNewComboName('');
      setNewComboItems([{ id: '1', productName: '', quantity: 1, unitPrice: 0 }]);
  };

  // --- Fix: Implemented deleteCombo function ---
  const deleteCombo = (id: string) => {
    const updated = combos.filter(c => c.id !== id);
    setCombos(updated);
    localStorage.setItem('metacheck_combos', JSON.stringify(updated));
  };

  // --- Fix: Implemented copyCombo function ---
  const copyCombo = (combo: Combo) => {
    const itemsText = combo.items.map(it => `• ${it.quantity}x ${it.productName}: R$ ${it.unitPrice.toFixed(2)}`).join('\n');
    const text = `📦 *COMBO: ${combo.name.toUpperCase()}*\n${itemsText}\n\n*Total: R$ ${combo.totalValue.toFixed(2)}*`;
    navigator.clipboard.writeText(text);
  };

  // --- Fix: Implemented updateComboItem function ---
  const updateComboItem = (id: string, field: keyof ComboItem, value: any) => {
    setNewComboItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  // --- Fix: Implemented handleRemoveComboItem function ---
  const handleRemoveComboItem = (id: string) => {
    if (newComboItems.length > 1) {
      setNewComboItems(prev => prev.filter(item => item.id !== id));
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Handshake className="text-brand-600" /> Negociação
            </h2>
            <p className="text-sm text-slate-500">Otimize suas propostas de venda</p>
        </div>
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner">
            <button onClick={() => setActiveTab('generator')} className={`flex-1 px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'generator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Gerador</button>
            <button onClick={() => setActiveTab('combos')} className={`flex-1 px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'combos' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Meus Combos</button>
        </div>
      </div>

      {activeTab === 'generator' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-30">
              <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block">Cliente</label>
              <div className="relative" ref={clientDropdownRef}>
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                <input type="text" value={clientSearch} onChange={(e) => { setClientSearch(e.target.value); setIsClientDropdownOpen(true); }} onFocus={() => setIsClientDropdownOpen(true)} className="w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-medium" placeholder="Buscar cliente..." />
                {isClientDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-48 overflow-y-auto z-40">
                    {filteredClients.map(c => (
                      <button key={c.id} onClick={() => { setSelectedClient(c); setClientSearch(c.name); setIsClientDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors">
                        <p className="font-bold text-sm text-slate-900 dark:text-white">{c.name}</p>
                        <p className="text-[10px] text-slate-500">#{c.code}</p>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-20">
              <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block">Produto</label>
              <div className="relative" ref={productDropdownRef}>
                <input type="text" value={productName} onChange={(e) => { setProductName(e.target.value); setIsProductDropdownOpen(true); }} onFocus={() => setIsProductDropdownOpen(true)} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-bold" placeholder="Nome ou Código..." />
                {isProductDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-48 overflow-y-auto z-40">
                    {smartProducts.map((p, i) => (
                      <button key={i} onClick={() => { setProductName(p.name); setPricePalm(p.price.toString()); setIsProductDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 flex justify-between items-center">
                        <div className="min-w-0 pr-2">
                           <p className="font-bold text-xs text-slate-700 dark:text-slate-300 truncate">{p.name}</p>
                           {p.source === 'history' && <span className="text-[8px] bg-amber-100 text-amber-700 px-1 rounded">HISTÓRICO</span>}
                        </div>
                        <span className="text-xs font-bold text-emerald-600">R$ {p.price.toFixed(2)}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
              <div className="grid grid-cols-2 gap-3 mt-4">
                <input type="number" placeholder="Qtd" value={quantity} onChange={(e) => setQuantity(e.target.value)} className="p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none" />
                <input type="number" placeholder="Preço Tabela" value={pricePalm} onChange={(e) => setPricePalm(e.target.value)} className="p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none" />
              </div>
            </div>

            <div className="bg-slate-900 p-5 rounded-2xl shadow-lg text-white">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] font-bold text-emerald-400 uppercase">Ação</h3>
                <div className="flex bg-white/10 p-1 rounded-lg">
                  <button onClick={() => setNegotiationType('bonus')} className={`px-3 py-1.5 rounded-md text-[10px] font-bold ${negotiationType === 'bonus' ? 'bg-emerald-500 text-white' : 'text-slate-400'}`}>Bonificar</button>
                  <button onClick={() => setNegotiationType('discount')} className={`px-3 py-1.5 rounded-md text-[10px] font-bold ${negotiationType === 'discount' ? 'bg-emerald-500 text-white' : 'text-slate-400'}`}>Desconto</button>
                </div>
              </div>
              {negotiationType === 'bonus' ? (
                <div className="space-y-3">
                  <input type="number" placeholder="Qtd Bonificada" value={bonusQty} onChange={(e) => setBonusQty(e.target.value)} className="w-full p-3 bg-white/10 border border-white/10 rounded-xl text-sm font-bold outline-none focus:border-emerald-500" />
                  <div className="flex justify-between items-center border-t border-white/10 pt-3">
                    <span className="text-xs text-slate-400">Preço Médio</span>
                    <span className="text-2xl font-black">R$ {genStats.finalPrice.toFixed(2)}</span>
                  </div>
                </div>
              ) : (
                <div className="space-y-3">
                  <input type="number" placeholder="Preço Target" value={targetPrice} onChange={(e) => setTargetPrice(e.target.value)} className="w-full p-3 bg-white/10 border border-white/10 rounded-xl text-sm font-bold outline-none focus:border-emerald-500" />
                  <div className="flex justify-between items-center border-t border-white/10 pt-3">
                    <span className="text-xs text-slate-400">Desconto</span>
                    <span className="text-2xl font-black">{genStats.investmentPercent.toFixed(1)}%</span>
                  </div>
                </div>
              )}
            </div>

            <button onClick={handleGenerate} className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 sticky bottom-4 md:static z-40">
                <FileText size={18} /> Gerar Negociação
            </button>
          </div>

          <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col min-h-[300px]" ref={resultRef}>
            <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-950/50">
                <h3 className="font-bold text-xs text-slate-500">RESUMO</h3>
                <button onClick={() => { navigator.clipboard.writeText(generatedText); setCopySuccess(true); setTimeout(() => setCopySuccess(false), 2000); }} disabled={!generatedText} className={`p-2 rounded-lg ${copySuccess ? 'text-emerald-500 bg-emerald-50' : 'text-slate-400 bg-slate-100'}`}>
                    {copySuccess ? <Check size={16} /> : <Copy size={16} />}
                </button>
            </div>
            <textarea readOnly value={generatedText} className="flex-1 p-5 outline-none bg-transparent text-sm font-mono text-slate-800 dark:text-slate-300 resize-none" placeholder="O resumo aparecerá aqui..." />
          </div>
        </div>
      )}

      {activeTab === 'combos' && (
        <div className="animate-in fade-in">
          {!isCreatingCombo ? (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Favoritos</h3>
                <button onClick={() => setIsCreatingCombo(true)} className="bg-brand-600 text-white px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 shadow-md">
                    <Plus size={16} /> Novo Combo
                </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {combos.map(c => (
                  <div key={c.id} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl p-4 shadow-sm group">
                    <div className="flex justify-between mb-3">
                       <h4 className="font-bold text-sm text-slate-800 dark:text-white uppercase">{c.name}</h4>
                       <div className="flex gap-2">
                          <button onClick={() => deleteCombo(c.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={14} /></button>
                          <button onClick={() => { copyCombo(c); setComboCopySuccess(c.id); setTimeout(() => setComboCopySuccess(null), 2000); }} className={`p-2 rounded-lg ${comboCopySuccess === c.id ? 'bg-emerald-50 text-emerald-600' : 'bg-brand-50 text-brand-600'}`}>
                             {comboCopySuccess === c.id ? <Check size={14}/> : <Copy size={14}/>}
                          </button>
                       </div>
                    </div>
                    <div className="space-y-1 bg-slate-50 dark:bg-slate-800/50 p-2 rounded-lg">
                       {c.items.map((it, idx) => (
                         <div key={idx} className="flex justify-between text-[10px] text-slate-500">
                           <span className="truncate pr-2">{it.quantity}x {it.productName}</span>
                           <span className="font-bold">R$ {it.unitPrice.toFixed(2)}</span>
                         </div>
                       ))}
                    </div>
                    <div className="mt-3 text-right">
                       <p className="text-xs font-black text-brand-600">Total: R$ {c.totalValue.toFixed(2)}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="bg-white dark:bg-slate-900 rounded-2xl border p-6 space-y-4 animate-in slide-in-from-right-4">
                <input value={newComboName} onChange={e => setNewComboName(e.target.value)} placeholder="Nome do Combo (ex: Mix Padaria)" className="w-full p-4 bg-slate-50 dark:bg-slate-950 border rounded-xl font-bold outline-none focus:ring-2 focus:ring-brand-500" />
                <div className="space-y-2">
                   {newComboItems.map(item => (
                     <div key={item.id} className="grid grid-cols-12 gap-2">
                        <input value={item.productName} onChange={e => updateComboItem(item.id, 'productName', e.target.value)} placeholder="Produto" className="col-span-6 p-2 bg-slate-50 dark:bg-slate-950 border rounded-lg text-xs" />
                        <input type="number" value={item.quantity} onChange={e => updateComboItem(item.id, 'quantity', parseFloat(e.target.value) || 0)} className="col-span-2 p-2 bg-slate-50 dark:bg-slate-950 border rounded-lg text-xs text-center" />
                        <input type="number" value={item.unitPrice} onChange={e => updateComboItem(item.id, 'unitPrice', parseFloat(e.target.value) || 0)} className="col-span-3 p-2 bg-slate-50 dark:bg-slate-950 border rounded-lg text-xs" />
                        <button onClick={() => handleRemoveComboItem(item.id)} className="col-span-1 text-slate-300 hover:text-red-500 flex justify-center items-center"><Trash2 size={16}/></button>
                     </div>
                   ))}
                   <button onClick={() => setNewComboItems([...newComboItems, { id: Date.now().toString(), productName: '', quantity: 1, unitPrice: 0 }])} className="w-full py-2 border border-dashed rounded-xl text-[10px] font-bold text-slate-400 hover:bg-slate-50">+ ADICIONAR ITEM</button>
                </div>
                <div className="flex justify-between items-center pt-4 border-t">
                    <p className="text-lg font-black text-brand-600">Total: R$ {newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0).toFixed(2)}</p>
                    <div className="flex gap-2">
                        <button onClick={() => setIsCreatingCombo(false)} className="px-4 py-2 text-xs font-bold text-slate-400">Cancelar</button>
                        <button onClick={saveCombo} className="bg-brand-600 text-white px-6 py-2 rounded-xl font-bold text-xs shadow-lg shadow-brand-500/20">Salvar</button>
                    </div>
                </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { DollarSign, Package, Copy, Check, Search, User, FileText, RefreshCw, Handshake, Percent, Gift, Box, Repeat, History, Plus, Trash2, Save, ShoppingBag, ArrowRight, LayoutGrid } from 'lucide-react';
import { useStore } from '../contexts/StoreContext';
import { Client } from '../types';

// Mock Data for "Quick Catalog"
const QUICK_PRODUCTS = [
    { code: '10213', name: 'CAFE MELITTA 500G', price: 16.12 },
    { code: '10214', name: 'CAFE MELITTA 250G', price: 8.45 },
    { code: '5050', name: 'TORRADA BAUDUCCO', price: 5.99 },
    { code: '3020', name: 'BOLINHO BAUDUCCO', price: 2.15 },
    { code: '7788', name: 'BISC. RECHEADO', price: 3.50 },
];

interface NegotiationHistoryItem {
    id: string;
    timestamp: number;
    clientName: string;
    productName: string;
    price: number;
    quantity: number;
    type: 'bonus' | 'discount';
    bonusQty: number;
    bonusType: 'same' | 'different';
    bonusProduct: string;
    bonusProductPrice: number;
    targetPrice: number;
}

interface ComboItem {
    id: string;
    productName: string;
    quantity: number;
    unitPrice: number;
}

interface Combo {
    id: string;
    name: string;
    items: ComboItem[];
    totalValue: number;
}

export const Negotiate: React.FC = () => {
  const { state } = useStore();
  const [activeTab, setActiveTab] = useState<'generator' | 'combos'>('generator');
  const [history, setHistory] = useState<NegotiationHistoryItem[]>([]);
  const [combos, setCombos] = useState<Combo[]>([]);
  const [isCreatingCombo, setIsCreatingCombo] = useState(false);

  // States for Generator
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [clientSearch, setClientSearch] = useState('');
  const [isClientDropdownOpen, setIsClientDropdownOpen] = useState(false);
  const [isProductDropdownOpen, setIsProductDropdownOpen] = useState(false);
  const [productName, setProductName] = useState(''); 
  const [quantity, setQuantity] = useState('');
  const [pricePalm, setPricePalm] = useState('');
  const [negotiationType, setNegotiationType] = useState<'bonus' | 'discount'>('bonus');
  const [bonusType, setBonusType] = useState<'same' | 'different'>('same');
  const [bonusProduct, setBonusProduct] = useState(''); 
  const [bonusQty, setBonusQty] = useState('');
  const [bonusProductPrice, setBonusProductPrice] = useState('');
  const [targetPrice, setTargetPrice] = useState('');
  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);
  const [comboCopySuccess, setComboCopySuccess] = useState<string | null>(null);

  // States for Combo Creation
  const [newComboName, setNewComboName] = useState('');
  const [newComboItems, setNewComboItems] = useState<ComboItem[]>([
      { id: '1', productName: '', quantity: 1, unitPrice: 0 }
  ]);

  const clientDropdownRef = useRef<HTMLDivElement>(null);
  const productDropdownRef = useRef<HTMLDivElement>(null);
  const resultRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedHist = localStorage.getItem('metacheck_negotiation_history');
    if (savedHist) setHistory(JSON.parse(savedHist));
    const savedCombos = localStorage.getItem('metacheck_combos');
    if (savedCombos) setCombos(JSON.parse(savedCombos));
  }, []);

  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  const smartProducts = useMemo(() => {
      const historyMap = new Map();
      history.forEach(h => {
         if (!historyMap.has(h.productName)) {
             historyMap.set(h.productName, { name: h.productName, price: h.price, source: 'history', lastDate: h.timestamp });
         }
      });
      QUICK_PRODUCTS.forEach(qp => {
          const fullName = `${qp.code} - ${qp.name}`;
          if (!historyMap.has(fullName)) {
              historyMap.set(fullName, { name: fullName, price: qp.price, source: 'catalog', lastDate: 0 });
          }
      });
      let all = Array.from(historyMap.values());
      if (productName) all = all.filter(p => p.name.toLowerCase().includes(productName.toLowerCase()));
      return all.sort((a, b) => b.lastDate - a.lastDate).slice(0, 8);
  }, [productName, history]);

  const genStats = useMemo(() => {
      const qty = parseFloat(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const totalValueSystem = qty * price;
      let finalPrice = price;
      let investmentPercent = 0;
      let bonusValueTotal = 0;

      if (negotiationType === 'bonus') {
          const bQty = parseFloat(bonusQty) || 0;
          if (bonusType === 'same') {
              finalPrice = (qty + bQty) > 0 ? totalValueSystem / (qty + bQty) : price;
              bonusValueTotal = bQty * price;
              investmentPercent = qty > 0 ? (bQty / qty) * 100 : 0; 
          } else {
              const otherPrice = parseFloat(bonusProductPrice.replace(',', '.')) || 0;
              bonusValueTotal = bQty * otherPrice;
              finalPrice = qty > 0 ? (totalValueSystem - bonusValueTotal) / qty : 0;
              investmentPercent = totalValueSystem > 0 ? (bonusValueTotal / totalValueSystem) * 100 : 0;
          }
      } else {
          const target = parseFloat(targetPrice.replace(',', '.')) || price;
          finalPrice = target;
          investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
          bonusValueTotal = (price - target) * qty; 
      }
      return { totalValueSystem, finalPrice, investmentPercent, bonusValueTotal };
  }, [quantity, pricePalm, bonusQty, targetPrice, negotiationType, bonusType, bonusProductPrice]);

  const handleGenerate = () => {
      if (!selectedClient) return alert("Selecione um cliente");
      if (!productName) return alert("Informe o produto");
      if (!quantity || !pricePalm) return alert("Informe quantidade e preço");

      const isBonus = negotiationType === 'bonus';
      const detail = isBonus 
        ? `Bonificação: ${bonusQty} unidades`
        : `Desconto direto para R$ ${parseFloat(targetPrice).toFixed(2)}`;

      const text = `
🛒 *PROPOSTA COMERCIAL*
*Cliente:* ${selectedClient.name}
*Produto:* ${productName.toUpperCase()}
*Qtd:* ${quantity} un.
*Preço Tabela:* R$ ${parseFloat(pricePalm).toFixed(2)}

*Condição:* ${detail}
*Economia:* ${genStats.investmentPercent.toFixed(1)}%
--------------------------
💰 *PREÇO FINAL: R$ ${genStats.finalPrice.toFixed(2)}*
--------------------------
      `.trim();

      setGeneratedText(text);

      // Salva no histórico
      const newItem: NegotiationHistoryItem = { 
        id: Date.now().toString(), 
        timestamp: Date.now(), 
        clientName: selectedClient.name, 
        productName, 
        price: parseFloat(pricePalm), 
