import React, { useState } from 'react';
import { User, Goal, UserRole, SaleLog, ActivationLog } from '../types';
import { Save, Settings, Briefcase, Target, User as UserIcon, Beaker, Trash2, Zap, BarChart3, RefreshCw } from 'lucide-react';
import { useStore } from '../contexts/StoreContext';

interface AdminProps {
  users: User[];
  goals: Goal[];
  onUpdateGoal: (goal: Goal) => void;
  onUpdateUser: (user: User) => void;
}

export const Admin: React.FC<AdminProps> = ({ users, goals, onUpdateGoal, onUpdateUser }) => {
  const { state, setState } = useStore();
  const [selectedUserId, setSelectedUserId] = useState<string>(users[0]?.id || '');
  const [salesTarget, setSalesTarget] = useState<number>(0);
  const [activationTarget, setActivationTarget] = useState<number>(0);
  const [industryTargets, setIndustryTargets] = useState<Record<string, number>>({});
  const [userMix, setUserMix] = useState<string>('MIX 2');
  const [showDevTools, setShowDevTools] = useState(false);

  React.useEffect(() => {
    const goal = goals.find(g => g.userId === selectedUserId && g.month === '2023-10');
    if (goal) { setSalesTarget(goal.salesTarget); setActivationTarget(goal.activationTarget); setIndustryTargets(goal.industryTargets || {}); } 
    else { setSalesTarget(0); setActivationTarget(0); setIndustryTargets({}); }
    const user = users.find(u => u.id === selectedUserId);
    if (user) { setUserMix(user.mix || 'MIX 2'); }
  }, [selectedUserId, goals, users]);

  const handleSave = () => {
    onUpdateGoal({ userId: selectedUserId, month: '2023-10', salesTarget, activationTarget, industryTargets });
    const user = users.find(u => u.id === selectedUserId);
    if (user) { onUpdateUser({ ...user, mix: userMix }); }
    alert('Configurações salvas.');
  };

  const handleIndustryTargetChange = (ind: string, valStr: string) => {
    const val = valStr === '' ? 0 : parseInt(valStr);
    if (!isNaN(val) && val >= 0) { setIndustryTargets(prev => ({ ...prev, [ind]: val })); }
  };

  // --- DEV TOOLS FUNCTIONS ---
  const simulateFullMeta = () => {
    if (!state.currentUser) return;
    const goal = goals.find(g => g.userId === state.currentUser?.id);
    if (!goal) return alert("Configure uma meta primeiro!");

    const target = goal.salesTarget || 10000;
    const fakeSale: SaleLog = {
      id: `dev-sale-${Date.now()}`,
      userId: state.currentUser.id,
      timestamp: new Date().toISOString(),
      clientName: state.clients[0]?.name || 'Cliente Teste',
      amount: target * 1.05, // 105% da meta
      items: ['Simulação Dev']
    };

    setState(prev => ({
      ...prev,
      salesLogs: [...prev.salesLogs, fakeSale]
    }));
    alert("Meta batida com sucesso! (Venda de " + (target * 1.05).toLocaleString('pt-BR') + " adicionada)");
  };

  const generateHistory = () => {
     if (!state.currentUser) return;
     const newLogs: SaleLog[] = [];
     const now = new Date();

     for(let i=1; i<=3; i++) {
        const date = new Date(now.getFullYear(), now.getMonth() - i, 15);
        newLogs.push({
           id: `hist-${i}-${Date.now()}`,
           userId: state.currentUser.id,
           timestamp: date.toISOString(),
           clientName: state.clients[0]?.name || 'Cliente Antigo',
           amount: 5000 + (Math.random() * 5000),
           items: ['Histórico']
        });
     }

