import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { AppState, User, Client, Goal, ActivationLog, UserRole, ClientUIState, View } from '../types';
import { getInitialState, persistState } from '../services/dataService';
import { getTrustedISOString, getTrustedLocalDateString } from '../services/timeService';

interface StoreContextType {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  currentView: View;
  setCurrentView: (view: View) => void;
  isDarkMode: boolean;
  toggleTheme: () => void;

  // Actions
  login: (email: string, pass: string) => void;
  register: (userData: Partial<User> & { password: string }) => void;
  logout: () => void;
  addActivationLog: (logData: Omit<ActivationLog, 'id'>) => void;
  addClient: (clientData: Omit<Client, 'id'>) => void;
  updateClient: (client: Client) => void;
  removeClient: (clientId: string) => void;
  updateGoal: (newGoal: Goal) => void;
  updateUser: (updatedUser: User) => void;
  updateClientUIState: (clientId: string, updates: Partial<ClientUIState>) => void;
  resetMonthlyData: () => void;
  restoreData: (backupData: any) => void;

  // Computed
  currentGoal?: Goal;
  userSales: any[];
  userActivations: ActivationLog[];
  userClientStates: Record<string, ClientUIState>;

  // PWA
  installPrompt: any;
  isIOS: boolean;
  isStandalone: boolean;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>(getInitialState());
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [isIOS, setIsIOS] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);

  // Initialize Theme
  useEffect(() => {
    const savedTheme = localStorage.getItem('metacheck_theme');
    if (savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setIsDarkMode(true);
      document.documentElement.classList.add('dark');
    } else {
      setIsDarkMode(false);
      document.documentElement.classList.remove('dark');
    }
  }, []);

  // DATA SANITIZATION EFFECT
  useEffect(() => {
    let hasChanges = false;
    let newClients = [...state.clients];
    let newUsers = [...state.users];

    const uniqueClientIds = new Set();
    const cleanClients: Client[] = [];
    for (let i = state.clients.length - 1; i >= 0; i--) {
        const c = state.clients[i];
        if (c && c.id && !uniqueClientIds.has(c.id)) {
            uniqueClientIds.add(c.id);
            cleanClients.unshift(c);
        } else if (c && c.id) {
            hasChanges = true;
        }
    }
    if (hasChanges) newClients = cleanClients;

    const uniqueUserIds = new Set();
    const cleanUsers: User[] = [];
    let userChanges = false;
    for (let i = state.users.length - 1; i >= 0; i--) {
        const u = state.users[i];
        if (u && u.id && !uniqueUserIds.has(u.id)) {
            uniqueUserIds.add(u.id);
            cleanUsers.unshift(u);
        } else if (u && u.id) {
            userChanges = true;
        }
    }
    if (userChanges) {
        newUsers = cleanUsers;
        hasChanges = true;
    }

    if (hasChanges) {
        setState(prev => ({ ...prev, clients: newClients, users: newUsers }));
    }
  }, []);

  useEffect(() => {
    const userAgent = window.navigator.userAgent.toLowerCase();
    const isIosDevice = /iphone|ipad|ipod/.test(userAgent);
    setIsIOS(isIosDevice);
    const isStandaloneMode = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone === true;
    setIsStandalone(isStandaloneMode);
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const toggleTheme = () => {
    setIsDarkMode(prev => {
      const newMode = !prev;
      if (newMode) document.documentElement.classList.add('dark');
      else document.documentElement.classList.remove('dark');
      localStorage.setItem('metacheck_theme', newMode ? 'dark' : 'light');
      return newMode;
    });
  };

  useEffect(() => {
    const timeoutId = setTimeout(() => {
      persistState(state);
    }, 800);
    return () => clearTimeout(timeoutId);
  }, [state]);

  useEffect(() => {
    if (state.currentUser && currentView === 'dashboard') {
      const today = new Date();
      const d = today.getDate();
      const m = today.getMonth();
      const y = today.getFullYear();
      const currentCycleIndex = d >= 20 ? (y * 12 + m + 1) : (y * 12 + m);
      const hasPlanning = (state.currentUser.workingDates || []).some(dateStr => {
         const [dy, dm, dd] = dateStr.split('-').map(Number);
         const dateMonthIndex = dm - 1;
         const dateCycleIdx = dd >= 20 ? (dy * 12 + dateMonthIndex + 1) : (dy * 12 + dateMonthIndex);
         return dateCycleIdx === currentCycleIndex;
      });
      if (!hasPlanning) {
        setCurrentView('profile');
      }
    }
  }, [state.currentUser, currentView]);

  const login = (email: string, pass: string) => {
    const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user) {
      if (user.password && user.password !== pass) {
        alert('Senha incorreta.');
        return;
      }
      setState(prev => ({ ...prev, currentUser: user }));
      setCurrentView('dashboard');
    } else {
      alert('Usuário não encontrado.');
    }
  };

  const register = (userData: Partial<User> & { password: string }) => {
    if (state.users.some(u => u.email.toLowerCase() === userData.email?.toLowerCase())) {
      alert('Este e-mail já está cadastrado.');
      return;
    }
    const uniqueUserId = `u${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
    const newUser: User = {
      id: uniqueUserId,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      password: userData.password,
      role: userData.role || UserRole.SALES,
      avatar: userData.avatar || 'https://picsum.photos/200',
      mix: userData.mix || 'MIX 2',
      industries: []
    };
    const newGoal: Goal = {
      userId: newUser.id,
      month: '2023-10',
      salesTarget: 0,
      activationTarget: 0,
      industryTargets: {}
    };
    setState(prev => ({
      ...prev,
      users: [...prev.users, newUser],
      goals: [...prev.goals, newGoal],
      currentUser: newUser
    }));
    setCurrentView('dashboard');
  };

  const logout = () => {
    setState(prev => ({ ...prev, currentUser: null }));
  };

  const addActivationLog = (logData: Omit<ActivationLog, 'id'>) => {
    const today = getTrustedLocalDateString();
    const timestamp = getTrustedISOString();
    setState(prev => {
      const existingLogIndex = prev.activationLogs.findIndex(log => {
        const logDate = new Date(log.timestamp).toLocaleDateString('pt-BR');
        return log.userId === logData.userId && 
               log.clientName === logData.clientName && 
               logDate === today;
      });
      if (existingLogIndex >= 0) {
        const updatedLogs = [...prev.activationLogs];
        updatedLogs[existingLogIndex] = {
          ...updatedLogs[existingLogIndex],
          ...logData,
          location: logData.location || updatedLogs[existingLogIndex].location,
        };
        return { ...prev, activationLogs: updatedLogs };
      } else {
        const uniqueLogId = `l${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
        const newLog: ActivationLog = {
          ...logData,
          id: uniqueLogId,
          timestamp: timestamp 
        };
        return { ...prev, activationLogs: [...prev.activationLogs, newLog] };
      }
    });
  };

  const addClient = (clientData: Omit<Client, 'id'>) => {
    const uniqueId = `c${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
    const newClient: Client = { 
        ...clientData, 
        id: uniqueId, 
        createdAt: clientData.createdAt || new Date().toISOString(),
        frequency: clientData.frequency || 'weekly'
    };
    setState(prev => ({ ...prev, clients: [...prev.clients, newClient] }));
  };

  const updateClient = (updatedClient: Client) => {
    setState(prev => ({
      ...prev,
      clients: prev.clients.map(c => c.id === updatedClient.id ? updatedClient : c)
    }));
  };

  const removeClient = (clientId: string) => {
    setState(prev => {
      const newClients = prev.clients.filter(c => c.id !== clientId);
      const newClientStates = { ...prev.clientStates };
      Object.keys(newClientStates).forEach(key => {
        if (key.endsWith(`_${clientId}`)) {
          delete newClientStates[key];
        }
      });
      return { ...prev, clients: newClients, clientStates: newClientStates };
    });
  };

  const updateGoal = (newGoal: Goal) => {
    setState(prev => {
      const otherGoals = prev.goals.filter(g => !(g.userId === newGoal.userId && g.month === newGoal.month));
      return { ...prev, goals: [...otherGoals, newGoal] };
    });
  };

  const updateUser = (updatedUser: User) => {
    setState(prev => {
      const updatedUsers = prev.users.map(u => u.id === updatedUser.id ? updatedUser : u);
      const updatedCurrentUser = prev.currentUser?.id === updatedUser.id ? updatedUser : prev.currentUser;
      return { ...prev, users: updatedUsers, currentUser: updatedCurrentUser };
    });
  };

  const updateClientUIState = (clientId: string, updates: Partial<ClientUIState>) => {
    setState(prev => {
      const currentUserId = prev.currentUser?.id || 'unknown';
      const storageKey = `${currentUserId}_${clientId}`;
      const current = prev.clientStates[storageKey] || { 
        clientId, isExpanded: false, isSaved: false, tasks: [] 
      };
      return {
        ...prev,
        clientStates: { ...prev.clientStates, [storageKey]: { ...current, ...updates } }
      };
    });
  };

  const resetMonthlyData = () => {
    const currentUserId = state.currentUser?.id;
    if (!currentUserId) return;
    setState(prev => ({
      ...prev,
      salesLogs: prev.salesLogs.filter(log => log.userId !== currentUserId),
      activationLogs: prev.activationLogs.filter(log => log.userId !== currentUserId),
      clientStates: {} 
    }));
  };

  const restoreData = (backupData: any) => {
    if (!backupData || typeof backupData !== 'object') {
        throw new Error("O arquivo selecionado não é um backup válido.");
    }
    if (Array.isArray(backupData)) {
       throw new Error("Este arquivo parece ser uma lista de clientes.");
    }
    setState(backupData);
    persistState(backupData);
  };

  const currentGoal = useMemo(() => 
    state.goals.find(g => g.userId === state.currentUser?.id && g.month === '2023-10'),
  [state.goals, state.currentUser?.id]);

  const userSales = useMemo(() => 
    state.salesLogs.filter(l => l.userId === state.currentUser?.id),
  [state.salesLogs, state.currentUser?.id]);

  const userActivations = useMemo(() => 
    state.activationLogs.filter(l => l.userId === state.currentUser?.id),
  [state.activationLogs, state.currentUser?.id]);

  const userClientStates = useMemo(() => {
    const states: Record<string, ClientUIState> = {};
    if (state.currentUser) {
      Object.keys(state.clientStates).forEach(key => {
          if (key.startsWith(`${state.currentUser?.id}_`)) {
              const clientId = key.split('_')[1];
              if (clientId) states[clientId] = state.clientStates[key];
          }
      });
    }
    return states;
  }, [state.clientStates, state.currentUser?.id]);

  return (
    <StoreContext.Provider value={{
      state, setState, currentView, setCurrentView, isDarkMode, toggleTheme,
      login, register, logout, addActivationLog, addClient, updateClient, removeClient, 
      updateGoal, updateUser, updateClientUIState, resetMonthlyData, restoreData,
      currentGoal, userSales, userActivations, userClientStates,
      installPrompt, isIOS, isStandalone
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error('useStore must be used within StoreProvider');
  return context;
};

