  const [newComboItems, setNewComboItems] = useState<ComboItem[]>([
      { id: '1', productName: '', quantity: 1, unitPrice: 0 }
  ]);

  const clientDropdownRef = useRef<HTMLDivElement>(null);
  const productDropdownRef = useRef<HTMLDivElement>(null);
  const resultRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedHist = localStorage.getItem('metacheck_negotiation_history');
    if (savedHist) setHistory(JSON.parse(savedHist));
    const savedCombos = localStorage.getItem('metacheck_combos');
    if (savedCombos) setCombos(JSON.parse(savedCombos));
  }, []);

  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  const smartProducts = useMemo(() => {
      const historyMap = new Map();
      history.forEach(h => {
         if (!historyMap.has(h.productName)) {
             historyMap.set(h.productName, { name: h.productName, price: h.price, source: 'history', lastDate: h.timestamp });
         }
      });
      QUICK_PRODUCTS.forEach(qp => {
          const fullName = `${qp.code} - ${qp.name}`;
          if (!historyMap.has(fullName)) {
              historyMap.set(fullName, { name: fullName, price: qp.price, source: 'catalog', lastDate: 0 });
          }
      });
      let all = Array.from(historyMap.values());
      if (productName) all = all.filter(p => p.name.toLowerCase().includes(productName.toLowerCase()));
      return all.sort((a, b) => b.lastDate - a.lastDate).slice(0, 8);
  }, [productName, history]);

  const genStats = useMemo(() => {
      const qty = parseFloat(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const totalValueSystem = qty * price;
      let finalPrice = price;
      let investmentPercent = 0;
      let diffValueTotal = 0;

      if (negotiationType === 'bonus') {
          const bQty = parseFloat(bonusQty) || 0;
          if (bonusType === 'same') {
              finalPrice = (qty + bQty) > 0 ? totalValueSystem / (qty + bQty) : price;
              diffValueTotal = bQty * price;
              investmentPercent = (qty + bQty) > 0 ? (bQty / (qty + bQty)) * 100 : 0; 
          } else {
              const otherPrice = parseFloat(bonusProductPrice.replace(',', '.')) || 0;
              diffValueTotal = bQty * otherPrice;
              finalPrice = qty > 0 ? (totalValueSystem - diffValueTotal) / qty : 0;
              investmentPercent = totalValueSystem > 0 ? (diffValueTotal / totalValueSystem) * 100 : 0;
          }
      } else {
          const target = parseFloat(targetPrice.replace(',', '.')) || price;
          finalPrice = target;
          investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
          diffValueTotal = (price - target) * qty; 
      }
      return { totalValueSystem, finalPrice, investmentPercent, diffValueTotal };
  }, [quantity, pricePalm, bonusQty, targetPrice, negotiationType, bonusType, bonusProductPrice]);

  const handleGenerate = () => {
      if (!selectedClient) return alert("Selecione um cliente");
      if (!productName) return alert("Informe o produto");
      if (!quantity || !pricePalm) return alert("Informe quantidade e preço");

      const formatCurrency = (val: number) => val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

      const isBonus = negotiationType === 'bonus';
      let text = "";

      if (isBonus) {
        text = `
🛒 *PROPOSTA COMERCIAL*

*Cliente:* ${selectedClient.name}
*Produto:* ${productName.toUpperCase()}
*Qtd:* ${quantity} und.
*Preço Tabela:* R$ ${formatCurrency(parseFloat(pricePalm))}
*Valor Pedido:* R$ ${formatCurrency(genStats.totalValueSystem)}

*CONDIÇÃO*
*Bonificação:* ${bonusQty} unidade
*Valor bonificação:* R$ ${formatCurrency(genStats.diffValueTotal)}
*Desconto:* ${genStats.investmentPercent.toFixed(1)}%
--------------------------
💰 *PREÇO FINAL: R$ ${formatCurrency(genStats.finalPrice)}*
--------------------------
        `.trim();
      } else {
        text = `
🛒 *PROPOSTA COMERCIAL*

*Cliente:* ${selectedClient.name}
*Produto:* ${productName.toUpperCase()}
*Qtd:* ${quantity} un.
*Preço Tabela:* R$ ${formatCurrency(parseFloat(pricePalm))}

*CONDIÇÃO:*
*Desconto direto para:* R$ ${formatCurrency(parseFloat(targetPrice))}
*Valor Desconto:* R$ ${formatCurrency(genStats.diffValueTotal)}
*Desconto:* ${genStats.investmentPercent.toFixed(1).replace('.', ',')}%
--------------------------
💰 *PREÇO FINAL: R$ ${formatCurrency(genStats.finalPrice)}*
--------------------------
        `.trim();
      }

      setGeneratedText(text);

      const newItem: NegotiationHistoryItem = { 
        id: Date.now().toString(), 
        timestamp: Date.now(), 
        clientName: selectedClient.name, 
        productName, 
        price: parseFloat(pricePalm), 
        quantity: parseInt(quantity), 
        type: negotiationType, 
        bonusQty: parseInt(bonusQty || '0'), 
        bonusType, 
        bonusProduct, 
        bonusProductPrice: parseFloat(bonusProductPrice || '0'), 
        targetPrice: parseFloat(targetPrice || '0') 
      };
      const newHist = [newItem, ...history].slice(0, 20);
      setHistory(newHist);
      localStorage.setItem('metacheck_negotiation_history', JSON.stringify(newHist));

      if (window.innerWidth < 768) {
          resultRef.current?.scrollIntoView({ behavior: 'smooth' });
      }
  };

  const saveCombo = () => {
      if (!newComboName) return alert("Dê um nome ao combo");
      const combo: Combo = { 
        id: Date.now().toString(), 
        name: newComboName, 
        items: newComboItems.filter(i => i.productName), 
        totalValue: newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0) 
      };
      const updated = [combo, ...combos];
      setCombos(updated);
      localStorage.setItem('metacheck_combos', JSON.stringify(updated));
      setIsCreatingCombo(false);
      setNewComboName('');
      setNewComboItems([{ id: '1', productName: '', quantity: 1, unitPrice: 0 }]);
  };

  const deleteCombo = (id: string) => {
    const updated = combos.filter(c => c.id !== id);
    setCombos(updated);
    localStorage.setItem('metacheck_combos', JSON.stringify(updated));
  };

  const copyCombo = (combo: Combo) => {
    const itemsText = combo.items.map(it => `• ${it.quantity}x ${it.productName}: R$ ${it.unitPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`).join('\n');
    const text = `📦 *COMBO: ${combo.name.toUpperCase()}*\n${itemsText}\n\n*Total: R$ ${combo.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}*`;
    navigator.clipboard.writeText(text);
  };

  const updateComboItem = (id: string, field: keyof ComboItem, value: any) => {
    setNewComboItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const handleRemoveComboItem = (id: string) => {
    if (newComboItems.length > 1) {
      setNewComboItems(prev => prev.filter(item => item.id !== id));
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Handshake className="text-brand-600" /> Negociação
            </h2>
            <p className="text-sm text-slate-500 font-medium">Simule e compartilhe propostas</p>
        </div>
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner">
            <button onClick={() => setActiveTab('generator')} className={`flex-1 px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'generator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Gerador</button>
            <button onClick={() => setActiveTab('combos')} className={`flex-1 px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'combos' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Meus Combos</button>
        </div>
      </div>

      {activeTab === 'generator' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
          <div className="space-y-4">
            {/* Seletor de Cliente */}
            <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-30">
              <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block tracking-widest">Cliente</label>
              <div className="relative" ref={clientDropdownRef}>
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                <input 
                  type="text" 
                  value={clientSearch} 
                  onChange={(e) => { setClientSearch(e.target.value); setIsClientDropdownOpen(true); }} 
                  onFocus={() => setIsClientDropdownOpen(true)} 
                  className="w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-medium" 
                  placeholder="Qual o cliente?" 
                />
                {isClientDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-48 overflow-y-auto z-40">
                    {filteredClients.map(c => (
                      <button key={c.id} onClick={() => { setSelectedClient(c); setClientSearch(c.name); setIsClientDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors">
                        <p className="font-bold text-sm text-slate-900 dark:text-white">{c.name}</p>
                        <p className="text-[10px] text-slate-500">#{c.code}</p>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {/* Input de Produto e Preço */}
            <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-20">
              <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block tracking-widest">Item e Valores</label>
              <div className="relative" ref={productDropdownRef}>
                <input 
                  type="text" 
                  value={productName} 
                  onChange={(e) => { setProductName(e.target.value); setIsProductDropdownOpen(true); }} 
                  onFocus={() => setIsProductDropdownOpen(true)} 
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-bold" 
                  placeholder="Nome do produto..." 
                />
                {isProductDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-48 overflow-y-auto z-40">
                    {smartProducts.map((p, i) => (
                      <button key={i} onClick={() => { setProductName(p.name); setPricePalm(p.price.toString()); setIsProductDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 flex justify-between items-center">
                        <div className="min-w-0 pr-2">
                           <p className="font-bold text-xs text-slate-700 dark:text-slate-300 truncate">{p.name}</p>
                           {p.source === 'history' && <span className="text-[8px] bg-amber-100 text-amber-700 px-1 rounded">HISTÓRICO</span>}
                        </div>
                        <span className="text-xs font-bold text-emerald-600">R$ {p.price.toFixed(2)}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
              <div className="grid grid-cols-2 gap-3 mt-4">
                <div className="space-y-1">
                   <span className="text-[9px] font-bold text-slate-400 uppercase ml-1">Qtd</span>
                   <input type="number" placeholder="0" value={quantity} onChange={(e) => setQuantity(e.target.value)} className="w-full p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none" />
                </div>
                <div className="space-y-1">
                   <span className="text-[9px] font-bold text-slate-400 uppercase ml-1">Preço Palm (R$)</span>
                   <input type="number" step="0.01" placeholder="0.00" value={pricePalm} onChange={(e) => setPricePalm(e.target.value)} className="w-full p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none" />
                </div>
              </div>
            </div>

            {/* Condição Comercial */}
            <div className="bg-slate-900 p-5 rounded-3xl shadow-lg text-white">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">Condição Especial</h3>
                <div className="flex bg-white/10 p-1 rounded-xl">
                  <button onClick={() => setNegotiationType('bonus')} className={`px-4 py-2 rounded-lg text-[10px] font-bold transition-all ${negotiationType === 'bonus' ? 'bg-brand-500 text-white shadow-lg' : 'text-slate-400'}`}>Bonificar</button>
                  <button onClick={() => setNegotiationType('discount')} className={`px-4 py-2 rounded-lg text-[10px] font-bold transition-all ${negotiationType === 'discount' ? 'bg-brand-500 text-white shadow-lg' : 'text-slate-400'}`}>Desconto</button>
                </div>
              </div>

              {negotiationType === 'bonus' ? (
                <div className="space-y-4">
                  <div className="space-y-1">
                     <span className="text-[10px] font-bold text-slate-400 uppercase ml-1">Qtd Bonificada</span>
                     <input type="number" placeholder="0" value={bonusQty} onChange={(e) => setBonusQty(e.target.value)} className="w-full p-4 bg-white/10 border border-white/10 rounded-2xl text-lg font-black outline-none focus:border-brand-500" />
                  </div>
                  <div className="flex justify-between items-center border-t border-white/10 pt-4">
                    <span className="text-xs text-slate-400 font-bold uppercase">Preço Médio Final</span>
                    <span className="text-3xl font-black text-emerald-400 tabular-nums">R$ {genStats.finalPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="space-y-1">
                     <span className="text-[10px] font-bold text-slate-400 uppercase ml-1">Preço Sugerido (R$)</span>
                     <input type="number" step="0.01" placeholder="0.00" value={targetPrice} onChange={(e) => setTargetPrice(e.target.value)} className="w-full p-4 bg-white/10 border border-white/10 rounded-2xl text-lg font-black outline-none focus:border-brand-500" />
                  </div>
                  <div className="flex justify-between items-center border-t border-white/10 pt-4">
                    <span className="text-xs text-slate-400 font-bold uppercase">Desconto Aplicado</span>
                    <span className="text-3xl font-black text-emerald-400 tabular-nums">{genStats.investmentPercent.toFixed(1).replace('.', ',')}%</span>
                  </div>
                </div>
              )}
            </div>

            {/* Ação de Gerar */}
            <button 
                onClick={handleGenerate} 
                className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 rounded-2xl shadow-xl shadow-brand-500/20 flex items-center justify-center gap-2 sticky bottom-4 md:static z-40 transition-transform active:scale-95"
            >
                <FileText size={20} /> Gerar Proposta
            </button>
          </div>

          {/* Resultado do Resumo */}
          <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col min-h-[350px] sticky top-24" ref={resultRef}>
            <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-950/50 rounded-t-3xl">
                <div className="flex items-center gap-2">
                    <div className="p-1.5 bg-brand-50 dark:bg-brand-900/20 text-brand-600 rounded-lg"><Repeat size={16} /></div>
                    <h3 className="font-bold text-xs text-slate-500 uppercase tracking-widest">Resumo para WhatsApp</h3>
                </div>
                <button 
                    onClick={() => { navigator.clipboard.writeText(generatedText); setCopySuccess(true); setTimeout(() => setCopySuccess(false), 2000); }} 
                    disabled={!generatedText} 
                    className={`p-2.5 rounded-xl transition-all ${copySuccess ? 'text-emerald-500 bg-emerald-50' : 'text-slate-400 bg-slate-100 dark:bg-slate-800 hover:text-brand-600 disabled:opacity-30'}`}
                >
                    {copySuccess ? <Check size={20} /> : <Copy size={20} />}
                </button>
            </div>
            <textarea 
                readOnly 
                value={generatedText} 
                className="flex-1 p-6 outline-none bg-transparent text-sm font-mono text-slate-800 dark:text-slate-300 resize-none leading-relaxed" 
                placeholder="Preencha os dados à esquerda e clique em 'Gerar Proposta'..." 
            />
          </div>
        </div>
      )}

      {activeTab === 'combos' && (
        <div className="animate-in fade-in space-y-6">
          {!isCreatingCombo ? (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest px-2">Estratégias Salvas</h3>
                <button onClick={() => setIsCreatingCombo(true)} className="bg-brand-600 text-white px-5 py-2.5 rounded-xl text-xs font-bold flex items-center gap-2 shadow-lg shadow-brand-500/20 transition-transform active:scale-95">
                    <Plus size={18} /> Criar Combo
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {combos.map(c => (
                  <div key={c.id} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl p-5 shadow-sm group">
                    <div className="flex justify-between items-start mb-4">
                       <div>
                          <h4 className="font-bold text-base text-slate-800 dark:text-white uppercase tracking-tight">{c.name}</h4>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">{c.items.length} Itens no Mix</p>
                       </div>
                       <div className="flex gap-1">
                          <button onClick={() => deleteCombo(c.id)} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={16} /></button>
                          <button 
                            onClick={() => { copyCombo(c); setComboCopySuccess(c.id); setTimeout(() => setComboCopySuccess(null), 2000); }} 
                            className={`p-2.5 rounded-xl transition-all ${comboCopySuccess === c.id ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 dark:bg-slate-800 text-slate-500 hover:text-brand-600'}`}
                          >
                             {comboCopySuccess === c.id ? <Check size={18}/> : <Copy size={18}/>}
                          </button>
                       </div>
                    </div>
                    <div className="space-y-2 bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl border border-slate-100 dark:border-slate-800">
                       {c.items.map((it, idx) => (
                         <div key={idx} className="flex justify-between text-xs text-slate-600 dark:text-slate-400">
                           <span className="truncate pr-4 font-medium">{it.quantity}x {it.productName}</span>
                           <span className="font-bold tabular-nums">R$ {it.unitPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                         </div>
                       ))}
                    </div>
                    <div className="mt-4 flex justify-between items-center">
                       <span className="text-[10px] font-bold text-slate-400 uppercase">Investimento Total</span>
                       <p className="text-xl font-black text-brand-600 tabular-nums">R$ {c.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                    </div>
                  </div>
                ))}

                {combos.length === 0 && (
                   <div className="col-span-full py-16 text-center bg-slate-50 dark:bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800">
                      <div className="w-16 h-16 bg-slate-200 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
                         <Package size={32} />
                      </div>
                      <p className="text-sm font-bold text-slate-500">Nenhum combo cadastrado.</p>
                      <p className="text-xs text-slate-400 mt-1">Crie estratégias de Mix para ganhar tempo na rua.</p>
                   </div>
                )}
              </div>
            </div>
          ) : (
            <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 p-6 space-y-6 shadow-xl animate-in slide-in-from-right-4">
                <div>
                   <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block tracking-widest">Nome da Estratégia</label>
                   <input 
                      value={newComboName} 
                      onChange={e => setNewComboName(e.target.value)} 
                      placeholder="Ex: Combo Padaria VIP" 
                      className="w-full p-4 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl font-bold text-lg outline-none focus:ring-2 focus:ring-brand-500" 
                   />
                </div>

                <div className="space-y-3">
                   <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block tracking-widest">Produtos do Mix</label>
                   {newComboItems.map(item => (
                     <div key={item.id} className="grid grid-cols-12 gap-2 items-center animate-in fade-in">
                        <input value={item.productName} onChange={e => updateComboItem(item.id, 'productName', e.target.value)} placeholder="Produto" className="col-span-6 p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 rounded-xl text-xs font-bold" />
                        <input type="number" value={item.quantity} onChange={e => updateComboItem(item.id, 'quantity', parseFloat(e.target.value) || 0)} placeholder="Qtd" className="col-span-2 p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 rounded-xl text-xs text-center font-bold" />
                        <input type="number" step="0.01" value={item.unitPrice} onChange={e => updateComboItem(item.id, 'unitPrice', parseFloat(e.target.value) || 0)} placeholder="R$" className="col-span-3 p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 rounded-xl text-xs font-bold" />
                        <button onClick={() => handleRemoveComboItem(item.id)} className="col-span-1 text-slate-300 hover:text-red-500 transition-colors flex justify-center"><Trash2 size={18}/></button>
                     </div>
                   ))}
                   <button 
                      onClick={() => setNewComboItems([...newComboItems, { id: Date.now().toString(), productName: '', quantity: 1, unitPrice: 0 }])} 
                      className="w-full py-3 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl text-xs font-bold text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors"
                   >
                      + ADICIONAR ITEM AO MIX
                   </button>
                </div>

                <div className="flex flex-col md:flex-row justify-between items-center gap-4 pt-6 border-t border-slate-100 dark:border-slate-800">
                    <div className="text-center md:text-left">
                       <p className="text-[10px] font-bold text-slate-400 uppercase">Investimento Sugerido</p>
                       <p className="text-3xl font-black text-brand-600 tabular-nums">R$ {newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                    </div>
                    <div className="flex gap-3 w-full md:w-auto">
                        <button onClick={() => setIsCreatingCombo(false)} className="flex-1 md:flex-none px-6 py-3.5 text-sm font-bold text-slate-500 bg-slate-100 dark:bg-slate-800 rounded-2xl">Cancelar</button>
