                  <div key={c.id} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl p-5 shadow-sm group hover:border-brand-300 transition-all">
                    <div className="flex justify-between items-start mb-4">
                       <div className="flex-1 min-w-0 pr-4">
                          <div className="flex items-center gap-2 mb-1">
                            <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded border ${getTagColor(c.tag || 'MIX')}`}>{c.tag || 'MIX'}</span>
