                   <button onClick={() => setIsCreatingCombo(false)} className="text-slate-400 hover:text-slate-600"><X size={20}/></button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div className="md:col-span-2">
                       <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block tracking-widest">Nome da Estratégia</label>
                       <input 
                          value={newComboName} 
                          onChange={e => setNewComboName(e.target.value)} 
                          placeholder="Ex: Combo Padaria VIP" 
                          className="w-full p-4 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl font-bold text-lg outline-none focus:ring-2 focus:ring-brand-500" 
                       />
                    </div>
                    <div>
                       <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block tracking-widest">Objetivo do Combo</label>
                       <select 
                          value={newComboTag}
                          onChange={e => setNewComboTag(e.target.value)}
                          className="w-full p-4 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl font-bold text-sm outline-none focus:ring-2 focus:ring-brand-500 h-[60px]"
                       >
                          <option value="MIX">Aumentar Mix</option>
                          <option value="GIRO">Preço / Giro Rápido</option>
                          <option value="MARGEM">Margem / Premium</option>
                       </select>
                    </div>
                </div>

                <div className="space-y-3">
                   <div className="flex justify-between items-center mb-1">
                      <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Produtos do Mix</label>
                      <div className="flex items-center gap-1 text-[10px] font-bold text-emerald-600">
                        <Calculator size={12} /> Calculadora de Markup Ativa (35%)
                      </div>
                   </div>
                   {newComboItems.map(item => (
                     <div key={item.id} className="grid grid-cols-12 gap-2 items-center animate-in fade-in">
                        <input value={item.productName} onChange={e => updateComboItem(item.id, 'productName', e.target.value)} placeholder="Produto" className="col-span-12 md:col-span-5 p-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-xs font-bold" />
                        <div className="col-span-4 md:col-span-2 relative">
                            <span className="absolute left-2 top-1 text-[8px] font-bold text-slate-400">QTD</span>
                            <input type="number" value={item.quantity} onChange={e => updateComboItem(item.id, 'quantity', parseFloat(e.target.value) || 0)} className="w-full pt-4 pb-2 px-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-xs text-center font-bold" />
                        </div>
                        <div className="col-span-4 md:col-span-2 relative">
                            <span className="absolute left-2 top-1 text-[8px] font-bold text-slate-400">R$ CUSTO</span>
                            <input type="number" step="0.01" value={item.unitPrice} onChange={e => {
                                const val = parseFloat(e.target.value) || 0;
                                updateComboItem(item.id, 'unitPrice', val);
                                updateComboItem(item.id, 'suggestedResalePrice', Math.round(val * 1.35 * 100) / 100);
                            }} className="w-full pt-4 pb-2 px-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-xs font-bold" />
                        </div>
                        <div className="col-span-3 md:col-span-2 relative">
                            <span className="absolute left-2 top-1 text-[8px] font-bold text-emerald-500">R$ SUG. VENDA</span>
                            <input type="number" step="0.01" value={item.suggestedResalePrice} onChange={e => updateComboItem(item.id, 'suggestedResalePrice', parseFloat(e.target.value) || 0)} className="w-full pt-4 pb-2 px-3 bg-emerald-50 dark:bg-emerald-900/10 border border-emerald-200 dark:border-emerald-800 rounded-xl text-xs font-bold text-emerald-700 dark:text-emerald-400" />
                        </div>
                        <button onClick={() => handleRemoveComboItem(item.id)} className="col-span-1 text-slate-300 hover:text-red-500 transition-colors flex justify-center"><Trash2 size={18}/></button>
                     </div>
                   ))}
                   <button 
                      onClick={() => setNewComboItems([...newComboItems, { id: Date.now().toString(), productName: '', quantity: 1, unitPrice: 0, suggestedResalePrice: 0 }])} 
                      className="w-full py-3 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl text-xs font-bold text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors"
                   >
                      + ADICIONAR ITEM AO MIX
                   </button>
                </div>

                <div className="flex flex-col md:flex-row justify-between items-center gap-4 pt-6 border-t border-slate-100 dark:border-slate-800">
                    <div className="text-center md:text-left">
                       <p className="text-[10px] font-bold text-slate-400 uppercase">Investimento Total Sugerido</p>
                       <p className="text-3xl font-black text-brand-600 tabular-nums">R$ {newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                    </div>
                    <div className="flex gap-3 w-full md:w-auto">
                        <button onClick={() => setIsCreatingCombo(false)} className="flex-1 md:flex-none px-6 py-3.5 text-sm font-bold text-slate-500 bg-slate-100 dark:bg-slate-800 rounded-2xl">Cancelar</button>
                        <button onClick={saveCombo} className="flex-1 md:flex-none bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-bold text-sm shadow-xl shadow-brand-500/20 active:scale-95 transition-transform">Salvar Estratégia</button>
                    </div>
                </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { View } from '../types';
import { useStore } from '../contexts/StoreContext';
import { LayoutDashboard, CheckCircle2, Trophy, Settings, LogOut, Building2, Sun, Moon, Handshake } from 'lucide-react';
import { ChatAssistant } from './ChatAssistant';

interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const { currentView, setCurrentView, state, logout, isDarkMode, toggleTheme } = useStore();
  const currentUser = state.currentUser;
  const [imgError, setImgError] = useState(false);

  if (!currentUser) return null;

  const NavItem = ({ view, icon: Icon, label }: { view: View; icon: any; label: string }) => {
    const isActive = currentView === view;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`flex flex-col items-center justify-center flex-1 py-1 relative transition-colors ${
          isActive ? 'text-brand-600 dark:text-brand-400' : 'text-slate-400 dark:text-slate-500'
        }`}
      >
        <Icon size={22} strokeWidth={isActive ? 2.5 : 2} />
        <span className="text-[10px] font-bold mt-1 tracking-tight">{label}</span>
        {isActive && <span className="absolute top-0 w-8 h-0.5 bg-brand-600 dark:bg-brand-400 rounded-full"></span>}
      </button>
    );
  };

  const UserAvatar = ({ className }: { className: string }) => {
     if (imgError || !currentUser.avatar) {
         return (
             <div className={`${className} bg-brand-600 text-white flex items-center justify-center font-bold`}>
                 {currentUser.name.charAt(0)}
             </div>
         );
     }
     return (
         <img 
            src={currentUser.avatar} 
            className={`${className} object-cover`} 
            alt="User" 
            onError={() => setImgError(true)}
         />
     );
  };

  return (
