import React, { useEffect, useState, useMemo } from 'react';
import { User, Goal, SaleLog, ActivationLog, Client } from '../types';
import { useStore } from '../contexts/StoreContext';
import { DollarSign, Copy, FileText, Smartphone, Globe, TrendingUp, Calendar, ArrowRight, X, Check, CheckCircle2, Zap, Target, Activity, Users, BarChart3, Layers, LayoutGrid, CalendarRange, AlertCircle, Building2, Package, ShoppingBag, MapPin, Trophy, Flame, ChevronRight } from 'lucide-react';
import { AreaChart, Area, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, Legend } from 'recharts';
import confetti from 'canvas-confetti';
import { getTrustedDate, getTrustedLocalDateString } from '../services/timeService';

interface DashboardProps {
  user: User;
  clients: Client[];
  goal?: Goal;
  sales: SaleLog[];
  activations: ActivationLog[];
}

export const Dashboard: React.FC<DashboardProps> = ({ user, clients, goal, sales, activations }) => {
  const { setCurrentView } = useStore();
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isTodaySummaryModalOpen, setIsTodaySummaryModalOpen] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);
  const [viewMode, setViewMode] = useState<'cycle' | 'week'>('cycle');

  // State for Industry Detail Modal
  const [selectedIndustry, setSelectedIndustry] = useState<string | null>(null);

  // --- SMART CYCLE LOGIC (Memoized) ---
  const { 
    currentCycleIndex, 
    remainingWorkingDays, 
    todayStr, 
    todayIso,
    todayDayName
  } = useMemo(() => {
    const todayDate = getTrustedDate();
    const todayDay = todayDate.getDate();
    const todayMonth = todayDate.getMonth();
    const todayYear = todayDate.getFullYear();
    const todayStr = getTrustedLocalDateString();
    const todayIso = todayDate.toISOString().split('T')[0];
    const todayDayName = ['Domingo', 'Segunda-feira', 'Terça-feira', 'Quarta-feira', 'Quinta-feira', 'Sexta-feira', 'Sábado'][todayDate.getDay()];

    const currentCycleIndex = todayDay >= 20 ? (todayYear * 12 + todayMonth + 1) : (todayYear * 12 + todayMonth);

    const cycleWorkingDates = (user.workingDates || []).filter(dateStr => {
      const [y, m, d] = dateStr.split('-').map(Number);
      const dateMonthIndex = m - 1; 
      const dateCycleIndex = d >= 20 ? (y * 12 + dateMonthIndex + 1) : (y * 12 + dateMonthIndex);
      return dateCycleIndex === currentCycleIndex;
    }).sort();

    const remainingWorkingDays = cycleWorkingDates.filter(d => d >= todayIso).length;

    return { currentCycleIndex, remainingWorkingDays, todayStr, todayIso, todayDayName };
  }, [user.workingDates]);

  // --- BASE CYCLE DATA ---
  const { cycleSales, cycleActivations } = useMemo(() => {
    const filterByCycle = (timestamp: string) => {
      const d = new Date(timestamp);
      const dateStr = d.toISOString().split('T')[0];
      const [y, m, day] = dateStr.split('-').map(Number);
      const dateCycleIdx = day >= 20 ? (y * 12 + (m - 1) + 1) : (y * 12 + (m - 1));
      return dateCycleIdx === currentCycleIndex;
    };

    return {
      cycleSales: sales.filter(s => filterByCycle(s.timestamp)),
      cycleActivations: activations.filter(a => filterByCycle(a.timestamp))
    };
  }, [sales, activations, currentCycleIndex]);

  // --- VIEW DATA ---
  const { viewSales, viewActivations } = useMemo(() => {
    if (viewMode === 'cycle') {
      return { viewSales: cycleSales, viewActivations: cycleActivations };
    } else {
      const now = getTrustedDate();
      const currentDay = now.getDay(); 
      const startOfWeek = new Date(now);
      startOfWeek.setDate(now.getDate() - currentDay);
      startOfWeek.setHours(0, 0, 0, 0);

      const endOfWeek = new Date(startOfWeek);
      endOfWeek.setDate(startOfWeek.getDate() + 6);
      endOfWeek.setHours(23, 59, 59, 999);

      const filterFn = (ts: string) => {
        const d = new Date(ts);
        return d >= startOfWeek && d <= endOfWeek;
      };

      return {
        viewSales: cycleSales.filter(s => filterFn(s.timestamp)),
        viewActivations: cycleActivations.filter(a => filterFn(a.timestamp))
      };
    }
  }, [viewMode, cycleSales, cycleActivations]);

  const { 
    totalSales, 
    totalPalmSales, 
    totalSiteSales, 
    totalActivations,
  } = useMemo(() => {
    const salesLogTotal = viewSales.reduce((acc, curr) => acc + curr.amount, 0); 
    const activationPalmTotal = viewActivations.reduce((acc, curr) => acc + (curr.saleValuePalm || 0), 0);
    const activationSiteTotal = viewActivations.reduce((acc, curr) => acc + (curr.saleValueSite || 0), 0);

    const totalPalmSales = salesLogTotal + activationPalmTotal;
    const totalSiteSales = activationSiteTotal;
    const totalSales = totalPalmSales + totalSiteSales;

    const totalActivations = viewActivations.filter(a => 
      (a.checklist && a.checklist.length > 0) || (a.saleValue || 0) > 0
    ).length;

    return { totalSales, totalPalmSales, totalSiteSales, totalActivations };
  }, [viewSales, viewActivations]);

  const { cycleTotalSales, cycleTotalCoverage } = useMemo(() => {
    const sTotal = cycleSales.reduce((acc, curr) => acc + curr.amount, 0);
    const palmTotal = cycleActivations.reduce((acc, curr) => acc + (curr.saleValuePalm || 0), 0);
    const siteTotal = cycleActivations.reduce((acc, curr) => acc + (curr.saleValueSite || 0), 0);
    const covTotal = new Set(cycleActivations.filter(a => 
        (a.checklist && a.checklist.length > 0) || (a.saleValue || 0) > 0
    ).map(a => a.clientName)).size;

    return { cycleTotalSales: sTotal + palmTotal + siteTotal, cycleTotalCoverage: covTotal };
  }, [cycleSales, cycleActivations]);

  const industryStats = useMemo(() => {
    return (user.industries || []).map(ind => {
      const target = goal?.industryTargets?.[ind] || 0;
      const realized = viewActivations.filter(a => a.checklist?.includes(ind)).length;
      const percent = target > 0 ? (realized / target) * 100 : 0;
      let statusColor = 'red';
      if (percent >= 100) statusColor = 'emerald';
      else if (percent >= 80) statusColor = 'blue';
      else if (percent >= 50) statusColor = 'amber';
      return { ind, target, realized, percent, statusColor };
    }).sort((a, b) => a.percent - b.percent);
  }, [user.industries, goal?.industryTargets, viewActivations]);

  const salesTarget = goal?.salesTarget || 1; 
  const salesPercent = Math.min(100, (totalSales / salesTarget) * 100);
  const actTarget = goal?.activationTarget || 1;
  const activationPercent = Math.min(100, (totalActivations / actTarget) * 100);
  const amountRemaining = Math.max(0, salesTarget - cycleTotalSales);
  const dailyRunRate = remainingWorkingDays > 0 ? amountRemaining / remainingWorkingDays : (amountRemaining > 0 ? amountRemaining : 0);
  const coverageRemaining = Math.max(0, actTarget - cycleTotalCoverage);
  const dailyCoverageRate = remainingWorkingDays > 0 ? Math.ceil(coverageRemaining / remainingWorkingDays) : coverageRemaining;

  const { todaySalesTotal, todayCoverageCount, dailyIndustryStats, routeFocus, todayDetails } = useMemo(() => {
    const todaySalesLogs = cycleSales.filter(s => new Date(s.timestamp).toLocaleDateString('pt-BR') === todayStr);
    const todayActs = cycleActivations.filter(a => new Date(a.timestamp).toLocaleDateString('pt-BR') === todayStr);

    const todaySalesTotal = 
      todaySalesLogs.reduce((acc, curr) => acc + curr.amount, 0) + 
      todayActs.reduce((acc, curr) => acc + (curr.saleValue || 0), 0);

    const doneClientNames = new Set(todayActs.filter(a => 
        (a.checklist && a.checklist.length > 0) || (a.saleValue || 0) > 0
    ).map(a => a.clientName));

    const todayCoverageCount = doneClientNames.size;

    const dailyIndustryStats = (user.industries || []).map(ind => {
         const cycleTarget = goal?.industryTargets?.[ind] || 0;
         const cycleRealized = cycleActivations.filter(a => a.checklist?.includes(ind)).length;
         const remaining = Math.max(0, cycleTarget - cycleRealized);
         const dailyNeed = remainingWorkingDays > 0 ? Math.ceil(remaining / remainingWorkingDays) : remaining;
         const todayRealized = todayActs.filter(a => a.checklist?.includes(ind)).length;
         return { name: ind, dailyNeed, todayRealized, isMet: todayRealized >= dailyNeed };
    });

    const todaysRouteClients = clients.filter(c => c.visitDay === todayDayName);
    const pendingClients = todaysRouteClients.filter(c => !doneClientNames.has(c.name));
    return { todaySalesTotal, todayCoverageCount, dailyIndustryStats, routeFocus: { totalRoute: todaysRouteClients.length, pendingCount: pendingClients.length, nextClientName: pendingClients[0]?.name }, todayDetails: [] };
  }, [cycleSales, cycleActivations, todayStr, dailyRunRate, clients, todayDayName, user.industries, goal?.industryTargets, remainingWorkingDays]);

  const ScorecardRow = ({ label, realized, target, type }: { label: string, realized: number, target: number, type: 'currency' | 'number' }) => {
     const percent = target > 0 ? (realized / target) * 100 : 0;
     const isMet = percent >= 100;
     return (
        <div className="mb-4 last:mb-0">
           <div className="flex justify-between items-end mb-1">
              <span className="text-[10px] font-bold text-white/70 uppercase tracking-wide">{label}</span>
              <div className="text-right">
                  <span className={`text-sm font-bold tabular-nums ${isMet ? 'text-emerald-300' : 'text-white'}`}>
                    {type === 'currency' ? `R$ ${realized.toLocaleString('pt-BR', { notation: 'compact' })}` : realized}
                  </span>
                  <span className="text-xs text-white/50 mx-1">/</span>
                  <span className="text-[10px] font-medium text-white/50 tabular-nums">
                    {type === 'currency' ? `R$ ${target.toLocaleString('pt-BR', { notation: 'compact' })}` : target}
                  </span>
              </div>
           </div>
           <div className="h-1.5 w-full bg-black/20 rounded-full overflow-hidden backdrop-blur-sm">
              <div className={`h-full transition-all duration-1000 ${isMet ? 'bg-emerald-400' : 'bg-brand-400'}`} style={{ width: `${Math.min(100, percent)}%` }}></div>
           </div>
        </div>
     );
  };

  return (
    <div className="space-y-4 animate-in fade-in duration-500 pb-10">

      {/* Header Selector */}
      <div className="flex justify-between items-center px-1">
        <div className="flex p-0.5 bg-slate-200 dark:bg-slate-800 rounded-lg">
             <button onClick={() => setViewMode('cycle')} className={`px-3 py-1.5 rounded-md text-[10px] font-black uppercase transition-all ${viewMode === 'cycle' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Ciclo</button>
             <button onClick={() => setViewMode('week')} className={`px-3 py-1.5 rounded-md text-[10px] font-black uppercase transition-all ${viewMode === 'week' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}>Semana</button>
        </div>
        <button onClick={() => setIsReportModalOpen(true)} className="p-2 text-slate-500 bg-white dark:bg-slate-900 rounded-lg shadow-sm">
            <FileText size={18} />
        </button>
      </div>

      {/* Hero Scorecard */}
      <div onClick={() => setIsTodaySummaryModalOpen(true)} className="relative overflow-hidden rounded-[2rem] shadow-lg shadow-brand-900/10 cursor-pointer active:scale-[0.98] transition-all">
         <div className="absolute inset-0 bg-gradient-to-br from-indigo-600 to-indigo-800"></div>
         <div className="relative z-10 p-6 text-white">
            <div className="flex justify-between items-start mb-6">
                <div>
                    <h2 className="text-lg font-black uppercase tracking-tight leading-none">Meta Hoje</h2>
                    <p className="text-[10px] text-white/60 font-bold uppercase mt-1">Status em tempo real</p>
                </div>
                <div className="bg-white/20 px-2.5 py-1 rounded-full text-[9px] font-black uppercase">Detelhes</div>
            </div>
            <ScorecardRow label="Venda vs Necessário" realized={todaySalesTotal} target={dailyRunRate} type="currency" />
            <ScorecardRow label="Cobertura vs Necessário" realized={todayCoverageCount} target={dailyCoverageRate} type="number" />

            <div className="mt-6 pt-5 border-t border-white/10">
                <span className="text-[10px] font-bold text-white/50 uppercase tracking-widest block mb-2">Mix Diário</span>
                <div className="grid grid-cols-2 gap-2">
                    {dailyIndustryStats.map(stat => (
                        <div key={stat.name} className={`px-2 py-1.5 rounded-lg border ${stat.isMet ? 'bg-emerald-500/20 border-emerald-500/30' : 'bg-white/5 border-white/10'} flex items-center justify-between`}>
                            <p className="text-[9px] font-bold text-white/90 uppercase truncate max-w-[50%]">{stat.name}</p>
                            <span className={`text-[10px] font-black ${stat.isMet ? 'text-emerald-300' : 'text-white'}`}>{stat.todayRealized}/{stat.dailyNeed}</span>
                        </div>
                    ))}
                </div>
            </div>
         </div>
      </div>

      {/* Roteiro Focus */}
      <div className="bg-white dark:bg-slate-900 rounded-2xl p-4 border border-slate-200 dark:border-slate-800 shadow-sm flex items-center gap-4">
          <div className="w-10 h-10 rounded-xl bg-brand-50 dark:bg-brand-900/20 text-brand-600 flex items-center justify-center shrink-0">
             <MapPin size={20} />
          </div>
          <div className="flex-1 min-w-0">
             <h3 className="text-sm font-bold text-slate-900 dark:text-white truncate">Roteiro de {todayDayName}</h3>
             <p className="text-[10px] text-slate-500 font-bold uppercase">
                {routeFocus.pendingCount > 0 ? `Faltam ${routeFocus.pendingCount} de ${routeFocus.totalRoute} PDVs` : 'Roteiro finalizado!'}
             </p>
          </div>
          <button onClick={() => setCurrentView('log-activation')} className="p-2 bg-brand-600 text-white rounded-xl shadow-md active:scale-90"><ChevronRight size={18} /></button>
      </div>

      {/* Main KPIs List */}
      <div className="space-y-3">
         <div className="bg-white dark:bg-slate-900 rounded-2xl p-4 border border-slate-200 dark:border-slate-800 flex justify-between items-center shadow-sm">
            <div>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Financeiro</p>
               <h4 className="text-xl font-black text-slate-900 dark:text-white tabular-nums">R$ {totalSales.toLocaleString('pt-BR')}</h4>
            </div>
            <div className="text-right">
               <span className="text-[10px] font-black text-brand-600 bg-brand-50 dark:bg-brand-900/20 px-2 py-1 rounded-md">{salesPercent.toFixed(1)}%</span>
               <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Meta: R$ {salesTarget.toLocaleString('pt-BR', {notation:'compact'})}</p>
            </div>
         </div>

         <div className="bg-white dark:bg-slate-900 rounded-2xl p-4 border border-slate-200 dark:border-slate-800 flex justify-between items-center shadow-sm">
            <div>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Cobertura</p>
               <h4 className="text-xl font-black text-slate-900 dark:text-white tabular-nums">{totalActivations} <span className="text-xs text-slate-400 font-medium">PDVs</span></h4>
            </div>
            <div className="text-right">
               <span className="text-[10px] font-black text-violet-600 bg-violet-50 dark:bg-violet-900/20 px-2 py-1 rounded-md">{activationPercent.toFixed(0)}%</span>
               <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Meta: {actTarget} PDVs</p>
            </div>
         </div>
      </div>

      {/* Industry Priority Grid */}
      <div className="bg-white dark:bg-slate-900 rounded-[2rem] p-5 border border-slate-200 dark:border-slate-800 shadow-sm">
         <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><Target size={14}/> Ranking Indústrias</h3>
         <div className="grid grid-cols-2 gap-3">
             {industryStats.map(item => (
                <button key={item.ind} onClick={() => setSelectedIndustry(item.ind)} className="flex flex-col gap-2 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800 text-left">
                    <span className="text-[9px] font-black text-slate-400 uppercase truncate">{item.ind}</span>
                    <div className="flex justify-between items-end">
                        <span className="text-lg font-black text-slate-900 dark:text-white tabular-nums">{item.realized}</span>
                        <span className={`text-[10px] font-black ${item.statusColor === 'emerald' ? 'text-emerald-500' : item.statusColor === 'red' ? 'text-red-500' : 'text-slate-500'}`}>{Math.round(item.percent)}%</span>
                    </div>
                    <div className="h-1 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                        <div className={`h-full ${item.statusColor === 'emerald' ? 'bg-emerald-500' : item.statusColor === 'amber' ? 'bg-amber-500' : 'bg-red-500'}`} style={{ width: `${Math.min(100, item.percent)}%` }}></div>
                    </div>
                </button>
             ))}
         </div>
      </div>
    </div>
  );
};

