import { GoogleGenAI } from "@google/genai";
import { User, Goal, SaleLog, ActivationLog, Client } from '../types';
import { getTrustedDate } from './timeService';

export const prepareContext = (user: User, clients: Client[], goal: Goal | undefined, sales: SaleLog[], activations: ActivationLog[]) => {
  const todayDate = getTrustedDate();
  const todayDay = todayDate.getDate();
  const todayMonth = todayDate.getMonth();
  const todayYear = todayDate.getFullYear();
  const todayIso = todayDate.toISOString().split('T')[0];

  // Identifica o índice do ciclo (Ex: se hoje é 20/12/2024, o ciclo é 202501)
  const currentCycleIndex = todayDay >= 20 ? (todayYear * 12 + todayMonth + 1) : (todayYear * 12 + todayMonth);

  const cycleWorkingDates = (user.workingDates || []).filter(dateStr => {
    const [y, m, d] = dateStr.split('-').map(Number);
    const dateCycleIndex = d >= 20 ? (y * 12 + (m - 1) + 1) : (y * 12 + (m - 1));
    return dateCycleIndex === currentCycleIndex;
  }).sort();

  const cycleStartDate = cycleWorkingDates[0] || 'Início do Ciclo';
  const cycleEndDate = cycleWorkingDates[cycleWorkingDates.length - 1] || 'Fim do Ciclo';
  const remainingWorkDaysCount = cycleWorkingDates.filter(d => d >= todayIso).length;

  const filterByCycle = (timestamp: string) => {
    const d = new Date(timestamp);
    const [y, m, day] = [d.getFullYear(), d.getMonth(), d.getDate()];
    const dateCycleIdx = day >= 20 ? (y * 12 + m + 1) : (y * 12 + m);
    return dateCycleIdx === currentCycleIndex;
  };

  const cycleSales = sales.filter(s => filterByCycle(s.timestamp));
  const cycleActivations = activations.filter(a => filterByCycle(a.timestamp));

  const historicalSalesTotal = cycleSales.reduce((acc, curr) => acc + curr.amount, 0);
  const palmTotal = cycleActivations.reduce((acc, curr) => acc + (curr.saleValuePalm || 0), 0);
  const siteTotal = cycleActivations.reduce((acc, curr) => acc + (curr.saleValueSite || 0), 0);
  const totalSales = historicalSalesTotal + palmTotal + siteTotal;

  const salesTarget = goal?.salesTarget || 1;
  const salesPercent = ((totalSales / salesTarget) * 100).toFixed(1);

  const uniqueActivatedClients = new Set(cycleActivations.filter(a => 
    (a.checklist && a.checklist.length > 0) || (a.saleValuePalm || 0) > 0 || (a.saleValueSite || 0) > 0
  ).map(a => a.clientName)).size;

  const activationTarget = goal?.activationTarget || 1;
  const industryStatus = (user.industries || []).map(ind => {
    const target = goal?.industryTargets?.[ind] || 0;
    const current = cycleActivations.filter(a => a.checklist?.includes(ind)).length;
    return `${ind}: ${current}/${target}`;
  }).join(', ');

  const needed = Math.max(0, salesTarget - totalSales);
  const runRate = remainingWorkDaysCount > 0 ? (needed / remainingWorkDaysCount).toFixed(2) : '0.00';

  return `
    DADOS DO CICLO ATUAL (${cycleStartDate} até ${cycleEndDate}):
    - Vendedor: ${user.name}
    - Dias Úteis Restantes: ${remainingWorkDaysCount}
    - Meta Ciclo: R$ ${salesTarget.toLocaleString('pt-BR')}
    - Realizado: R$ ${totalSales.toLocaleString('pt-BR')} (${salesPercent}%)
    - Run Rate Necessário: R$ ${runRate} / dia
    - Positividade: ${uniqueActivatedClients} de ${activationTarget} PDVs
    - Indústrias: ${industryStatus}
  `;
};

export const createChatSession = async (user: User, clients: Client[], goal: Goal | undefined, sales: SaleLog[], activations: ActivationLog[]) => {
  if (!process.env.API_KEY) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const contextData = prepareContext(user, clients, goal, sales, activations);

  const percentMatch = contextData.match(/\(([\d.]+)%\)/);
  const percent = percentMatch ? parseFloat(percentMatch[1]) : 0;

  let persona = "CONSULTOR ESTRATÉGICO";
  if (percent >= 100) persona = "A LENDA VIVA (Comemorativo)";
  else if (percent >= 80) persona = "COACH MOTIVADOR (Foco no fechamento)";
  else if (percent < 50) persona = "GERENTE DURÃO (Foco em recuperação)";

  const systemInstruction = `
    Você é o Coach MetaCheck. Persona: ${persona}.
    Sua missão é ajudar o vendedor a bater a meta do ciclo (Corte dia 20).

    DADOS ATUAIS:
    ${contextData}

    REGRAS:
    1. Seja conciso (máximo 3 parágrafos).
    2. Sempre sugira o Run Rate se o vendedor estiver abaixo da meta.
    3. Use negrito para valores R$.
    4. Termine OBRIGATORIAMENTE com: [SUGGESTIONS: Pergunta 1 | Pergunta 2 | Pergunta 3]
  `;

  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: { systemInstruction }
  });
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, Goal } from '../types';
