interface ProfileProps {
  user: User;
  onUpdateUser: (user: User) => void;
  goal?: Goal;
  onUpdateGoal: (goal: Goal) => void;
  onResetData: () => void;
  onLogout: () => void;
}

export const Profile: React.FC<ProfileProps> = ({ user, onUpdateUser, goal, onUpdateGoal, onResetData, onLogout }) => {
  const { state, restoreData, installPrompt, isIOS, isStandalone } = useStore();
  const [activeTab, setActiveTab] = useState<'planning' | 'account'>('planning');
  const [name, setName] = useState(user.name);
  const [email, setEmail] = useState(user.email);
  const [avatar, setAvatar] = useState(user.avatar);
  const [mix, setMix] = useState(user.mix || 'MIX 2');
  const [workingDates, setWorkingDates] = useState<string[]>(user.workingDates || []);
  const [salesTarget, setSalesTarget] = useState<number>(0);
  const [activationTarget, setActivationTarget] = useState<number>(0);
  const [industryTargets, setIndustryTargets] = useState<Record<string, number>>({});
  const [industries, setIndustries] = useState<string[]>(user.industries || []);
  const [newIndustry, setNewIndustry] = useState('');

  const [viewDate, setViewDate] = useState(() => {
    const d = new Date();
    if (d.getDate() >= 20) d.setMonth(d.getMonth() + 1);
    return d;
  });

  const currentCycleKey = useMemo(() => {
    return `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}`;
  }, [viewDate]);

  useEffect(() => {
    if (goal) {
      setSalesTarget(goal.salesTarget);
      setActivationTarget(goal.activationTarget);
      setIndustryTargets(goal.industryTargets || {});
    } else {
      setSalesTarget(0);
      setActivationTarget(0);
      setIndustryTargets({});
    }
  }, [goal, currentCycleKey]);

  const isPlanningValid = useMemo(() => {
    if (activeTab !== 'planning') return true;
    return salesTarget > 0 && activationTarget > 0 && workingDates.length > 0 && industries.length > 0;
  }, [activeTab, salesTarget, activationTarget, workingDates, industries]);

  const handleSave = () => {
    onUpdateUser({ ...user, name, email, avatar, mix, workingDates, industries });
    onUpdateGoal({
        userId: user.id,
        month: currentCycleKey,
        salesTarget,
        activationTarget,
        industryTargets
    });
    alert('Planejamento do Ciclo salvo com sucesso!');
  };

  const addIndustry = () => {
    if (newIndustry && !industries.includes(newIndustry)) {
      setIndustries([...industries, newIndustry]);
      setNewIndustry('');
    }
  };

  const removeIndustry = (ind: string) => setIndustries(industries.filter(i => i !== ind));

  const toggleDate = (dateStr: string) => {
    setWorkingDates(prev => prev.includes(dateStr) ? prev.filter(d => d !== dateStr) : [...prev, dateStr].sort());
  };

  const handleDragStart = (dateStr: string) => toggleDate(dateStr);
  const handleAutoFill = () => {
    const targetYear = viewDate.getFullYear();
    const targetMonth = viewDate.getMonth();
    const startDate = new Date(targetYear, targetMonth - 1, 20);
    const endDate = new Date(targetYear, targetMonth, 19);
    const updatedDates = new Set(workingDates);
    let iterator = new Date(startDate);
    while (iterator <= endDate) {
        if (iterator.getDay() !== 0 && iterator.getDay() !== 6) {
            updatedDates.add(`${iterator.getFullYear()}-${String(iterator.getMonth() + 1).padStart(2, '0')}-${String(iterator.getDate()).padStart(2, '0')}`);
        }
        iterator.setDate(iterator.getDate() + 1);
    }
    setWorkingDates(Array.from(updatedDates).sort());
  };

  const changeMonth = (offset: number) => {
    const newDate = new Date(viewDate);
    newDate.setMonth(newDate.getMonth() + offset);
    setViewDate(newDate);
  };

  const { days, firstDay, year, month } = useMemo(() => {
    const d = viewDate;
    return { 
        days: new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate(),
        firstDay: new Date(d.getFullYear(), d.getMonth(), 1).getDay(),
        year: d.getFullYear(),
        month: d.getMonth()
    };
  }, [viewDate]);

  return (
    <div className="max-w-4xl mx-auto pb-24 animate-in fade-in duration-300">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
        <div className="flex items-center gap-4">
           <div className="w-16 h-16 rounded-full bg-brand-600 text-white flex items-center justify-center font-bold text-2xl shadow-md border-2 border-white">
              {user.name.charAt(0)}
           </div>
           <div>
             <h2 className="text-2xl font-bold text-slate-900 dark:text-white">{user.name}</h2>
             <p className="text-sm text-slate-500 font-medium">Ciclo: {currentCycleKey}</p>
           </div>
        </div>
        <button onClick={handleSave} disabled={!isPlanningValid} className="bg-brand-600 hover:bg-brand-700 disabled:opacity-50 text-white px-6 py-3 rounded-xl font-bold shadow-lg flex items-center gap-2 transition-all active:scale-95 text-sm">
           <Save size={18} /> Salvar Ciclo
        </button>
      </div>

      <div className="flex gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl mb-8">
         <button onClick={() => setActiveTab('planning')} className={`flex-1 py-2.5 rounded-xl text-sm font-bold flex items-center justify-center gap-2 ${activeTab === 'planning' ? 'bg-white text-brand-600 shadow-sm' : 'text-slate-500'}`}><Target size={18} /> Planejamento</button>
         <button onClick={() => setActiveTab('account')} className={`flex-1 py-2.5 rounded-xl text-sm font-bold flex items-center justify-center gap-2 ${activeTab === 'account' ? 'bg-white text-brand-600 shadow-sm' : 'text-slate-500'}`}><Settings size={18} /> Conta</button>
      </div>

      {activeTab === 'planning' && (
        <div className="space-y-6">
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm">
                <h3 className="font-bold text-lg mb-6 text-slate-900 dark:text-white">Metas do Período</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Venda Alvo (R$)</label>
                       <input type="number" value={salesTarget} onChange={e => setSalesTarget(Number(e.target.value))} className="w-full p-4 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl font-bold text-xl" />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Cobertura Alvo (PDVs)</label>
                       <input type="number" value={activationTarget} onChange={e => setActivationTarget(Number(e.target.value))} className="w-full p-4 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl font-bold text-xl" />
                    </div>
                </div>
            </div>

            <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm">
                <div className="flex justify-between items-center mb-6">
                   <h3 className="font-bold text-lg text-slate-900 dark:text-white">Dias de Campo</h3>
                   <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-950 p-1 rounded-xl">
                      <button onClick={() => changeMonth(-1)} className="p-2 text-slate-500"><ChevronLeft size={18} /></button>
                      <span className="font-bold text-xs w-24 text-center uppercase">{viewDate.toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' })}</span>
                      <button onClick={() => changeMonth(1)} className="p-2 text-slate-500"><ChevronRight size={18} /></button>
                   </div>
                </div>

                <div className="flex gap-2 mb-4 overflow-x-auto pb-2 scrollbar-hide">
                    <button onClick={handleAutoFill} className="flex items-center gap-2 px-3 py-2 bg-brand-50 text-brand-700 rounded-lg text-[10px] font-bold whitespace-nowrap"><Wand2 size={14} /> Auto-Preencher Ciclo</button>
                    <button onClick={() => setWorkingDates([])} className="flex items-center gap-2 px-3 py-2 bg-red-50 text-red-600 rounded-lg text-[10px] font-bold whitespace-nowrap"><Eraser size={14} /> Limpar Tudo</button>
                </div>

                <div className="grid grid-cols-7 gap-2 touch-none">
                   {['D','S','T','Q','Q','S','S'].map(d => <div key={d} className="text-center text-[10px] font-bold text-slate-400 py-2">{d}</div>)}
                   {Array.from({ length: firstDay }).map((_, i) => <div key={i}></div>)}
                   {Array.from({ length: days }).map((_, i) => {
                      const day = i + 1;
                      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                      const isSelected = workingDates.includes(dateStr);
                      return (
                        <button key={day} onClick={() => handleDragStart(dateStr)} className={`aspect-square rounded-xl flex items-center justify-center text-sm font-bold transition-all ${isSelected ? 'bg-brand-600 text-white shadow-md' : 'bg-slate-50 dark:bg-slate-800 text-slate-400 border border-slate-100 dark:border-slate-700'}`}>
                           {day}
                        </button>
                      );
                   })}
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

