const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>(getInitialState());
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [isIOS, setIsIOS] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('metacheck_theme');
    if (savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setIsDarkMode(true);
      document.documentElement.classList.add('dark');
    }
  }, []);

  const toggleTheme = () => {
    setIsDarkMode(prev => {
      const next = !prev;
      if (next) document.documentElement.classList.add('dark');
      else document.documentElement.classList.remove('dark');
      localStorage.setItem('metacheck_theme', next ? 'dark' : 'light');
      return next;
    });
  };

  useEffect(() => {
    const timer = setTimeout(() => persistState(state), 1000);
    return () => clearTimeout(timer);
  }, [state]);

  const currentGoal = useMemo(() => {
    if (!state.currentUser) return undefined;
    const now = getTrustedDate();
    const cycleMonth = now.getDate() >= 20 ? now.getMonth() + 1 : now.getMonth();
    const cycleYear = now.getDate() >= 20 && now.getMonth() === 11 ? now.getFullYear() + 1 : now.getFullYear();
    const cycleKey = `${cycleYear}-${String((cycleMonth % 12) + 1).padStart(2, '0')}`;

    return state.goals.find(g => g.userId === state.currentUser?.id && g.month === cycleKey) 
           || state.goals.find(g => g.userId === state.currentUser?.id); // Fallback
  }, [state.goals, state.currentUser]);

  const login = (email: string, pass: string) => {
    const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user && user.password === pass) {
      setState(prev => ({ ...prev, currentUser: user }));
      setCurrentView('dashboard');
    } else alert('Credenciais inválidas');
  };

  const register = (userData: Partial<User> & { password: string }) => {
    const newUser: User = { id: `u${Date.now()}`, name: userData.name || '', email: userData.email || '', password: userData.password, role: UserRole.SALES, avatar: userData.avatar || '', mix: userData.mix || 'MIX 2', industries: [] };
    setState(prev => ({ ...prev, users: [...prev.users, newUser], currentUser: newUser }));
    setCurrentView('dashboard');
  };

  const logout = () => setState(prev => ({ ...prev, currentUser: null }));

  const addActivationLog = (logData: Omit<ActivationLog, 'id'>) => {
    const timestamp = getTrustedISOString();
    const id = `l${Date.now()}`;
    setState(prev => ({ ...prev, activationLogs: [...prev.activationLogs, { ...logData, id, timestamp }] }));
  };

  const addClient = (c: Omit<Client, 'id'>) => setState(prev => ({ ...prev, clients: [...prev.clients, { ...c, id: `c${Date.now()}` }] }));
  const updateClient = (c: Client) => setState(prev => ({ ...prev, clients: prev.clients.map(cl => cl.id === c.id ? c : cl) }));
  const removeClient = (id: string) => setState(prev => ({ ...prev, clients: prev.clients.filter(c => c.id !== id) }));
  const updateGoal = (g: Goal) => setState(prev => {
    const filtered = prev.goals.filter(goal => !(goal.userId === g.userId && goal.month === g.month));
    return { ...prev, goals: [...filtered, g] };
  });
  const updateUser = (u: User) => setState(prev => ({ ...prev, users: prev.users.map(us => us.id === u.id ? u : us), currentUser: prev.currentUser?.id === u.id ? u : prev.currentUser }));
  const updateClientUIState = (id: string, up: Partial<ClientUIState>) => setState(prev => {
    const key = `${prev.currentUser?.id}_${id}`;
    return { ...prev, clientStates: { ...prev.clientStates, [key]: { ...(prev.clientStates[key] || { clientId: id, isExpanded: false, isSaved: false, tasks: [] }), ...up } } };
  });

  const resetMonthlyData = () => setState(prev => ({ ...prev, salesLogs: [], activationLogs: [], clientStates: {} }));
  const restoreData = (d: any) => { setState(d); persistState(d); };

  const userSales = useMemo(() => state.salesLogs.filter(l => l.userId === state.currentUser?.id), [state.salesLogs, state.currentUser?.id]);
  const userActivations = useMemo(() => state.activationLogs.filter(l => l.userId === state.currentUser?.id), [state.activationLogs, state.currentUser?.id]);
  const userClientStates = useMemo(() => {
    const res: Record<string, ClientUIState> = {};
    Object.keys(state.clientStates).forEach(k => { if (k.startsWith(`${state.currentUser?.id}_`)) res[k.split('_')[1]] = state.clientStates[k]; });
    return res;
  }, [state.clientStates, state.currentUser?.id]);

  return (
    <StoreContext.Provider value={{
      state, setState, currentView, setCurrentView, isDarkMode, toggleTheme,
      login, register, logout, addActivationLog, addClient, updateClient, removeClient, 
      updateGoal, updateUser, updateClientUIState, resetMonthlyData, restoreData,
      currentGoal, userSales, userActivations, userClientStates, installPrompt, isIOS, isStandalone
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const c = useContext(StoreContext);
  if (!c) throw new Error('StoreProvider missing');
  return c;
};

import { GoogleGenAI } from "@google/genai";
import { User, Goal, SaleLog, ActivationLog, Client } from '../types';
import { getTrustedDate } from './timeService';

export const prepareContext = (user: User, clients: Client[], goal: Goal | undefined, sales: SaleLog[], activations: ActivationLog[]) => {
  const todayDate = getTrustedDate();
  const todayIso = todayDate.toISOString().split('T')[0];
  const todayDay = todayDate.getDate();
  const todayMonth = todayDate.getMonth();
  const todayYear = todayDate.getFullYear();

  // Ciclo comercial: inicia dia 20
  const currentCycleIndex = todayDay >= 20 ? (todayYear * 12 + todayMonth + 1) : (todayYear * 12 + todayMonth);

  // Filtragem de dias úteis apenas do ciclo atual
  const cycleWorkingDates = (user.workingDates || []).filter(dateStr => {
    const [y, m, d] = dateStr.split('-').map(Number);
    const dateCycleIndex = d >= 20 ? (y * 12 + (m - 1) + 1) : (y * 12 + (m - 1));
    return dateCycleIndex === currentCycleIndex;
  }).sort();

  const remainingWorkDays = cycleWorkingDates.filter(d => d >= todayIso).length;

  const filterByCycle = (timestamp: string) => {
    const d = new Date(timestamp);
    const [y, m, day] = [d.getFullYear(), d.getMonth(), d.getDate()];
    const dateCycleIdx = day >= 20 ? (y * 12 + m + 1) : (y * 12 + m);
    return dateCycleIdx === currentCycleIndex;
  };

  const cycleSales = sales.filter(s => filterByCycle(s.timestamp));
  const cycleActivations = activations.filter(a => filterByCycle(a.timestamp));

  const totalSales = cycleSales.reduce((acc, curr) => acc + curr.amount, 0) + 
                     cycleActivations.reduce((acc, curr) => acc + (curr.saleValuePalm || 0) + (curr.saleValueSite || 0), 0);

  const salesTarget = goal?.salesTarget || 1;
  const uniqueActivated = new Set(cycleActivations.filter(a => 
    (a.checklist && a.checklist.length > 0) || (a.saleValuePalm || 0) > 0 || (a.saleValueSite || 0) > 0
  ).map(a => a.clientName)).size;

  const needed = Math.max(0, salesTarget - totalSales);
  const runRate = remainingWorkDays > 0 ? (needed / remainingWorkDays) : 0;

  return `
    CONTEXTO DE VENDAS (Ciclo Atual):
    - Realizado: R$ ${totalSales.toLocaleString('pt-BR')}
    - Meta: R$ ${salesTarget.toLocaleString('pt-BR')}
    - PDVs Positivados: ${uniqueActivated} de ${goal?.activationTarget || 0}
    - Dias úteis restantes: ${remainingWorkDays}
    - Run Rate necessário: R$ ${runRate.toLocaleString('pt-BR')} por dia útil restante.
  `;
};

export const createChatSession = async (user: User, clients: Client[], goal: Goal | undefined, sales: SaleLog[], activations: ActivationLog[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const contextData = prepareContext(user, clients, goal, sales, activations);

  const systemInstruction = `
    Você é o Consultor MetaCheck. Sua missão é analisar os dados e dar ordens claras de venda.
    Sempre foque no Run Rate diário. Se o vendedor estiver abaixo de 80% da meta, seja mais incisivo.
    DADOS: ${contextData}
    Termine com: [SUGGESTIONS: Pergunta 1 | Pergunta 2]
  `;

  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: { systemInstruction }
  });
};

