/**
 * Lógica de Precificação Comercial:
 * Preço Sugerido = Custo / (1 - Margem_Desejada)
 * Ex: Custo 10.00 com Margem 30% -> 10 / 0.7 = 14.28
 */
const calculateSuggestedPrice = (cost: number, margin: number = 0.30) => {
    if (cost <= 0) return 0;
    const price = cost / (1 - margin);
    return Math.round(price * 100) / 100;
};

