  useEffect(() => {
    const savedCombos = localStorage.getItem('metacheck_combos');
    if (savedCombos) setCombos(JSON.parse(savedCombos));

    const draft = localStorage.getItem('metacheck_combo_draft');
    if (draft) {
        const parsed = JSON.parse(draft);
        setNewComboName(parsed.name || '');
        setNewComboTag(parsed.tag || 'MIX');
        setNewComboItems(parsed.items || [{ id: '1', productName: '', quantity: 1, unitPrice: 0, suggestedResalePrice: 0 }]);
        if (parsed.items?.length > 0) setIsCreatingCombo(true);
    }
  }, []);

  // Salvar rascunho automaticamente ao editar
  useEffect(() => {
    if (isCreatingCombo) {
        localStorage.setItem('metacheck_combo_draft', JSON.stringify({
            name: newComboName,
            tag: newComboTag,
            items: newComboItems
        }));
    }
  }, [newComboName, newComboTag, newComboItems, isCreatingCombo]);

  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  const currentComboTotal = useMemo(() => {
    return newComboItems.reduce((acc, it) => acc + (it.quantity * it.unitPrice), 0);
  }, [newComboItems]);

  const applyStrategicSuggestion = (suggestion: typeof STRATEGIC_SUGGESTIONS[0]) => {
    setIsCreatingCombo(true);
    setNewComboName(suggestion.name);
    setNewComboTag(suggestion.tag);
    setNewComboItems(suggestion.items.map((it, idx) => ({
      id: `${Date.now()}-${idx}`,
      productName: it.productName,
      quantity: it.quantity,
      unitPrice: it.unitPrice,
      suggestedResalePrice: calculateSuggestedPrice(it.unitPrice, 0.30)
    })));
  };

  const saveCombo = () => {
      if (!newComboName.trim()) return alert("Dê um nome ao combo estratégico.");
      const validItems = newComboItems.filter(i => i.productName.trim() !== '' && i.unitPrice > 0);
      if (validItems.length === 0) return alert("Adicione pelo menos um item válido com preço.");

      const combo: Combo = { 
        id: Date.now().toString(), 
        name: newComboName, 
        tag: newComboTag,
        items: validItems, 
        totalValue: currentComboTotal
      };

      const updated = [combo, ...combos];
      setCombos(updated);
      localStorage.setItem('metacheck_combos', JSON.stringify(updated));
      localStorage.removeItem('metacheck_combo_draft'); // Limpa rascunho após salvar

      setIsCreatingCombo(false);
      setNewComboName('');
      setNewComboItems([{ id: '1', productName: '', quantity: 1, unitPrice: 0, suggestedResalePrice: 0 }]);
